                            <div className="bg-green-50 border border-green-200 rounded-lg p-4 flex flex-col items-center gap-3 animate-fade-in shadow-sm">
                              <div className="flex items-center gap-2 text-green-700 font-bold text-sm text-center">
                                <CheckCircleIcon className="h-5 w-5 flex-shrink-0" />
                                <span>Assinatura coletada com sucesso</span>
                              </div>
                              <button 
                                onClick={() => setViewSignatureUrl(order.signature!)}
