import React, { useState, useEffect } from 'react';
import { FinancialParams, RecurringOrderConfig, Product, OrderItem, RecurrenceType, Company } from '../types';
import Card from './common/Card';
import Input from './common/Input';
import Button from './common/Button';
import { TrashIcon, PlusIcon, CalendarDaysIcon, ArrowPathIcon, UsersIcon } from './Icons';

interface FinancialParametersProps {
  params: FinancialParams;
  recurringConfig?: RecurringOrderConfig;
  companyName: string;
  availableProducts: Product[];
  onUpdate: (newParams: FinancialParams, newRecurring?: RecurringOrderConfig) => void;
}

const FinancialParameters: React.FC<FinancialParametersProps> = ({ params, recurringConfig, companyName, availableProducts, onUpdate }) => {
  const [financialData, setFinancialData] = useState<FinancialParams>(params);
  const [items, setItems] = useState<Omit<OrderItem, 'id'>[]>(recurringConfig?.items || []);
  const [recurrenceType, setRecurrenceType] = useState<RecurrenceType>(recurringConfig?.recurrence.type || 'daily');
  const [hasChanges, setHasChanges] = useState(false);

  useEffect(() => {
    setFinancialData(params);
    setItems(recurringConfig?.items || []);
    setRecurrenceType(recurringConfig?.recurrence.type || 'daily');
    setHasChanges(false);
  }, [params, recurringConfig]);

  const handleFinancialChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFinancialData(prev => ({
      ...prev,
      [name]: parseFloat(value) || 0,
    }));
    setHasChanges(true);
  };

  const handleAddItem = () => {
    setItems([...items, { productName: '', quantity: 1 }]);
    setHasChanges(true);
  };

  const handleRemoveItem = (index: number) => {
    setItems(items.filter((_, i) => i !== index));
    setHasChanges(true);
  };

  const handleItemChange = (index: number, field: 'productName' | 'quantity', value: string | number) => {
    const newItems = [...items];
    if (field === 'quantity') {
      newItems[index][field] = Number(value) < 1 ? 1 : Number(value);
    } else {
      newItems[index][field] = value as string;
    }
    setItems(newItems);
    setHasChanges(true);
  };

  const handleRecurrenceTypeChange = (type: RecurrenceType) => {
    setRecurrenceType(type);
    setHasChanges(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    let finalRecurring: RecurringOrderConfig | undefined = undefined;

    const validItems = items.filter(it => it.productName !== '');
    if (validItems.length > 0) {
      finalRecurring = {
        items: validItems,
        recurrence: {
          type: recurrenceType,
          interval: 1
        }
      };
    }

    onUpdate(financialData, finalRecurring);
    setHasChanges(false);
    alert('Configurações de compra e recorrência salvas!');
  };

  const handleCancel = () => {
    setFinancialData(params);
    setItems(recurringConfig?.items || []);
    setRecurrenceType(recurringConfig?.recurrence.type || 'daily');
    setHasChanges(false);
  }

  return (
    <div className="mt-6 space-y-6 animate-fade-in">
      <Card>
        <form onSubmit={handleSubmit} className="p-8">
            <h3 className="text-xl font-semibold text-amber-800 mb-2">Parâmetros de {companyName}</h3>
            <p className="text-sm text-amber-600 mb-8">Defina as configurações financeiras e de recorrência para esta empresa.</p>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-10">
                <Input
                    label="Margem de Lucro Padrão (%)"
                    name="defaultMargin"
                    type="number"
                    value={financialData.defaultMargin}
                    onChange={handleFinancialChange}
                    step="0.1"
                    min="0"
                />
                <Input
                    label="Taxa de Entrega Padrão (R$)"
                    name="defaultDeliveryFee"
                    type="number"
                    value={financialData.defaultDeliveryFee}
                    onChange={handleFinancialChange}
                    step="0.01"
                    min="0"
                />
                <Input
                    label="Desconto Máximo (%)"
                    name="maxDiscount"
                    type="number"
                    value={financialData.maxDiscount}
                    onChange={handleFinancialChange}
                    step="0.1"
                    min="0"
                    max="100"
                />
            </div>

            <div className="border-t border-orange-100 pt-8">
                <h4 className="text-lg font-bold text-amber-800 mb-4 flex items-center gap-2">
                    <CalendarDaysIcon className="h-6 w-6 text-orange-500" />
                    Agendamento Recorrente (Compra Automática)
                </h4>

                <div className="space-y-6">
                    {/* Items section */}
                    <div className="bg-orange-50/50 p-4 rounded-lg border border-orange-100">
                        <label className="block text-sm font-bold text-amber-700 mb-3">Itens do Pedido Recorrente</label>
                        <div className="space-y-3">
                            {items.map((item, index) => (
                                <div key={index} className="flex items-end gap-3">
                                    <div className="flex-1">
                                        <select
                                            value={item.productName}
                                            onChange={(e) => handleItemChange(index, 'productName', e.target.value)}
                                            className="w-full px-4 py-2 bg-white border border-orange-200 rounded-md shadow-sm focus:ring-orange-500 focus:border-orange-500 text-sm"
                                        >
                                            <option value="" disabled>Escolha o produto</option>
                                            {availableProducts.map(p => (
                                                <option key={p.id} value={p.name}>{p.name}</option>
                                            ))}
                                        </select>
                                    </div>
                                    <div className="w-24">
                                        <Input
                                            label=""
                                            type="number"
                                            value={item.quantity}
                                            onChange={(e) => handleItemChange(index, 'quantity', e.target.value)}
                                            className="h-[42px]"
                                        />
                                    </div>
                                    <button 
                                        type="button" 
                                        onClick={() => handleRemoveItem(index)}
                                        className="p-2.5 text-red-400 hover:text-red-600 transition-colors"
                                    >
                                        <TrashIcon className="h-5 w-5" />
                                    </button>
                                </div>
                            ))}
                            <button
                                type="button"
                                onClick={handleAddItem}
                                className="flex items-center text-sm font-bold text-orange-600 hover:text-orange-700 mt-2"
                            >
                                <PlusIcon className="h-4 w-4 mr-1" /> Adicionar Produto
                            </button>
                        </div>
                    </div>

                    {/* Frequency section */}
                    <div>
                        <label className="block text-sm font-bold text-amber-700 mb-3">Frequência de Geração</label>
                        <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                            <button
                                type="button"
                                onClick={() => handleRecurrenceTypeChange('daily')}
                                className={`flex items-center justify-center gap-2 p-3 rounded-lg border-2 font-bold transition-all ${
                                    recurrenceType === 'daily' ? 'bg-orange-500 border-orange-600 text-white shadow-md' : 'bg-white border-orange-200 text-amber-700 hover:bg-orange-50'
                                }`}
                            >
                                <ArrowPathIcon className="h-5 w-5" />
                                Diário
                            </button>
                            <button
                                type="button"
                                onClick={() => handleRecurrenceTypeChange('weekdays')}
                                className={`flex items-center justify-center gap-2 p-3 rounded-lg border-2 font-bold transition-all ${
                                    recurrenceType === 'weekdays' ? 'bg-orange-500 border-orange-600 text-white shadow-md' : 'bg-white border-orange-200 text-amber-700 hover:bg-orange-50'
                                }`}
                            >
                                <UsersIcon className="h-5 w-5" />
                                Dias Úteis (Seg-Sex)
                            </button>
                            <button
                                type="button"
                                onClick={() => handleRecurrenceTypeChange('weekly')}
                                className={`flex items-center justify-center gap-2 p-3 rounded-lg border-2 font-bold transition-all ${
                                    recurrenceType === 'weekly' ? 'bg-orange-500 border-orange-600 text-white shadow-md' : 'bg-white border-orange-200 text-amber-700 hover:bg-orange-50'
                                }`}
                            >
                                <CalendarDaysIcon className="h-5 w-5" />
                                Semanal
                            </button>
                        </div>
                    </div>
                </div>
            </div>

             <div className="mt-10 flex justify-end gap-4 border-t border-orange-100 pt-8">
                <Button type="button" variant="secondary" onClick={handleCancel} disabled={!hasChanges}>
                    Cancelar
                </Button>
                <Button type="submit" disabled={!hasChanges}>
                    Salvar Alterações
                </Button>
            </div>
        </form>
      </Card>
    </div>
  );
};

export default FinancialParameters;

import React, { useState, useEffect } from 'react';
import { Company, Product, CompanyProductSetting, FinancialParams, RecurringOrderConfig } from '../types';
