                  </li>
                ))}
              </ul>
            </Card>
          ) : (
             <Card className="text-center p-12">
                <ClipboardDocumentListIcon className="mx-auto h-12 w-12 text-gray-400" />
                <h3 className="mt-2 text-lg font-medium text-gray-900">Nenhum pedido confirmado encontrado</h3>
                <p className="mt-1 text-sm text-gray-500">Comece adicionando o primeiro pedido para {selectedCompany.name}.</p>
             </Card>
          )}
        </div>
      ) : (
         <Card className="text-center p-12">
            <BuildingStorefrontIcon className="mx-auto h-12 w-12 text-gray-400" />
            <h3 className="mt-2 text-lg font-medium text-gray-900">Nenhuma empresa selecionada</h3>
            <p className="mt-1 text-sm text-gray-500">Por favor, selecione uma empresa acima para ver o histórico.</p>
         </Card>
      )}
    </div>
  );
};

export default OrderManagement;

import React, { useState } from 'react';
import { Company, Order, OrderItem } from '../types';
import Card from './common/Card';
import Button from './common/Button';
import { CheckCircleIcon, TrashIcon, CalendarDaysIcon, RocketLaunchIcon, XMarkIcon, ChevronRightIcon } from './Icons';

interface ScheduledConfirmationProps {
  companies: Company[];
  onConfirmOrder: (companyId: string, orderId: string) => void;
  onDeleteOrder: (companyId: string, orderId: string) => void;
  onLaunchBatch: (orders: { companyId: string, order: Omit<Order, 'id'> }[]) => void;
}

const ScheduledConfirmation: React.FC<ScheduledConfirmationProps> = ({ companies, onConfirmOrder, onDeleteOrder, onLaunchBatch }) => {
  const [isOverviewOpen, setIsOverviewOpen] = useState(false);
  const [selectedCompanies, setSelectedCompanies] = useState<string[]>([]);

  // Pedidos já existentes (pendentes)
  const pendingOrders = companies.flatMap(c => 
    c.orders
      .filter(o => o.status === 'pending')
      .map(o => ({ company: c, order: o }))
  );

  // Lógica para prever pedidos de AMANHÃ
  const getTomorrowInfo = () => {
    const tomorrow = new Date();
    tomorrow.setDate(tomorrow.getDate() + 1);
    const tomorrowStr = tomorrow.toISOString().split('T')[0];
    const tomorrowDay = tomorrow.getDay(); // 0-6

    const companiesWithRecurrence = companies.filter(c => {
      if (!c.recurringOrder) return false;
      const { type } = c.recurringOrder.recurrence;

      // Verifica se já existe pedido lançado para amanhã
      const alreadyHasTomorrow = c.orders.some(o => o.date === tomorrowStr);
      if (alreadyHasTomorrow) return false;

      if (type === 'daily') return true;
      if (type === 'weekdays') return tomorrowDay >= 1 && tomorrowDay <= 5;
      if (type === 'weekly') return true; // Simplificado
      return false;
    });

    return { tomorrowStr, companiesWithRecurrence };
  };

  const { tomorrowStr, companiesWithRecurrence } = getTomorrowInfo();

  const handleOpenOverview = () => {
    setSelectedCompanies(companiesWithRecurrence.map(c => c.id));
    setIsOverviewOpen(true);
  };

  const handleConfirmLaunch = () => {
    const ordersToLaunch = companiesWithRecurrence
      .filter(c => selectedCompanies.includes(c.id))
      .map(c => ({
        companyId: c.id,
        order: {
          date: tomorrowStr,
          items: c.recurringOrder!.items.map((it, idx) => ({ ...it, id: `item-auto-${idx}-${Date.now()}` })),
          status: 'pending' as const
        }
      }));

    onLaunchBatch(ordersToLaunch);
    setIsOverviewOpen(false);
    alert(`${ordersToLaunch.length} pedidos lançados para amanhã!`);
  };

  const toggleCompanySelection = (id: string) => {
    setSelectedCompanies(prev => 
      prev.includes(id) ? prev.filter(item => item !== id) : [...prev, id]
    );
  };

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Action Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 bg-white p-6 rounded-xl shadow-sm border border-orange-100">
        <div>
          <h2 className="text-lg font-bold text-amber-800">Ações de Agendamento</h2>
          <p className="text-sm text-amber-600">Lance pedidos antecipadamente para organizar a produção.</p>
        </div>
        <Button 
          onClick={handleOpenOverview} 
          disabled={companiesWithRecurrence.length === 0}
          className="w-full sm:w-auto shadow-lg shadow-orange-200"
        >
          <RocketLaunchIcon className="h-5 w-5 mr-2" />
          Lançar pedidos de amanhã ({companiesWithRecurrence.length})
        </Button>
      </div>

      {/* List of Pending Orders */}
      <div className="space-y-4">
        <h3 className="text-sm font-bold text-amber-700 uppercase tracking-wider ml-1">Pedidos Aguardando Confirmação</h3>
        {pendingOrders.length === 0 ? (
          <Card className="text-center p-12">
            <CheckCircleIcon className="mx-auto h-12 w-12 text-green-400" />
            <h3 className="mt-2 text-lg font-medium text-gray-900">Tudo em dia!</h3>
            <p className="mt-1 text-sm text-gray-500">Não há pedidos pendentes no momento.</p>
          </Card>
        ) : (
          pendingOrders.map(({ company, order }) => (
            <Card key={order.id} className="p-0 border-l-4 border-orange-400 hover:shadow-md transition-shadow">
              <div className="p-6">
                <div className="flex flex-col md:flex-row justify-between gap-6">
                  <div className="flex-1 space-y-4">
                    <div className="flex items-center gap-3">
                      <img src={company.logoUrl} alt={company.name} className="h-10 w-10 rounded-full border border-orange-100" />
                      <div>
                        <div className="flex items-center gap-2">
                            <h3 className="text-lg font-bold text-amber-800">{company.name}</h3>
                            {order.date > new Date().toISOString().split('T')[0] && (
                                <span className="bg-blue-100 text-blue-700 text-[10px] font-bold px-2 py-0.5 rounded-full uppercase">Antecipado</span>
                            )}
                        </div>
                        <p className="text-xs text-amber-600 flex items-center gap-1">
                          <CalendarDaysIcon className="h-3 w-3" />
                          Data: {new Date(order.date).toLocaleDateString('pt-BR', { timeZone: 'UTC' })}
                        </p>
                      </div>
                    </div>

                    <div className="bg-orange-50/50 rounded-lg p-4 border border-orange-100">
                      <ul className="grid grid-cols-1 sm:grid-cols-2 gap-x-6 gap-y-2">
                        {order.items.map(item => (
                          <li key={item.id} className="flex justify-between text-sm border-b border-orange-100/50 pb-1">
                            <span className="text-gray-700">{item.productName}</span>
                            <span className="font-bold text-amber-800">{item.quantity} un.</span>
                          </li>
                        ))}
                      </ul>
                    </div>
                  </div>

                  <div className="flex flex-col sm:flex-row md:flex-col justify-center gap-3">
                    <Button onClick={() => onConfirmOrder(company.id, order.id)} className="flex-1 sm:flex-none">
                      <CheckCircleIcon className="h-5 w-5 mr-2" />
                      Confirmar
                    </Button>
                    <Button 
                        variant="secondary" 
                        onClick={() => onDeleteOrder(company.id, order.id)}
                        className="text-red-600 border-red-200 hover:bg-red-50 flex-1 sm:flex-none"
                    >
                      <TrashIcon className="h-5 w-5 mr-2" />
                      Descartar
                    </Button>
                  </div>
                </div>
              </div>
            </Card>
          ))
        )}
      </div>

      {/* Tomorrow Overview Modal */}
      {isOverviewOpen && (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4 backdrop-blur-sm animate-fade-in">
          <Card className="w-full max-w-3xl max-h-[90vh] flex flex-col shadow-2xl">
            <div className="p-6 border-b border-orange-100 flex justify-between items-center bg-orange-50/30">
              <div>
                <h3 className="text-xl font-bold text-amber-800 flex items-center gap-2">
                  <RocketLaunchIcon className="h-6 w-6 text-orange-500" />
                  Overview de Pedidos para Amanhã
                </h3>
                <p className="text-sm text-amber-600">Data prevista: {new Date(tomorrowStr).toLocaleDateString('pt-BR', { timeZone: 'UTC', day: '2-digit', month: 'long' })}</p>
              </div>
              <button onClick={() => setIsOverviewOpen(false)} className="text-gray-400 hover:text-gray-600">
                <XMarkIcon className="h-6 w-6" />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-4">
              <div className="bg-blue-50 border border-blue-200 rounded-lg p-4 text-sm text-blue-700 mb-4">
                Selecione as empresas para as quais deseja lançar o pedido agendado agora.
              </div>

              {companiesWithRecurrence.map(company => (
                <div 
                  key={company.id} 
                  onClick={() => toggleCompanySelection(company.id)}
                  className={`flex items-start gap-4 p-4 rounded-xl border-2 transition-all cursor-pointer ${
                    selectedCompanies.includes(company.id) 
                    ? 'border-orange-500 bg-orange-50 shadow-sm' 
                    : 'border-gray-100 bg-white grayscale opacity-70'
                  }`}
                >
                  <div className={`mt-1 h-6 w-6 rounded-full border-2 flex items-center justify-center flex-shrink-0 transition-colors ${
                    selectedCompanies.includes(company.id) ? 'bg-orange-500 border-orange-500 text-white' : 'border-gray-300 bg-white'
                  }`}>
                    {selectedCompanies.includes(company.id) && <CheckCircleIcon className="h-4 w-4" />}
                  </div>

                  <div className="flex-1">
                    <div className="flex justify-between items-center mb-2">
                      <span className="font-bold text-amber-800">{company.name}</span>
                      <span className="text-[10px] font-bold text-orange-600 uppercase bg-orange-100 px-2 py-0.5 rounded">
                        {company.recurringOrder?.recurrence.type}
                      </span>
                    </div>
                    <div className="flex flex-wrap gap-2">
                      {company.recurringOrder?.items.map((it, i) => (
                        <span key={i} className="text-xs bg-white border border-orange-100 px-2 py-1 rounded text-gray-600">
                          {it.quantity}x {it.productName}
                        </span>
                      ))}
                    </div>
                  </div>
                </div>
              ))}
            </div>

            <div className="p-6 border-t border-orange-100 flex justify-end gap-3 bg-gray-50/50">
              <Button variant="secondary" onClick={() => setIsOverviewOpen(false)}>Cancelar</Button>
              <Button onClick={handleConfirmLaunch} disabled={selectedCompanies.length === 0}>
                Confirmar e Lançar {selectedCompanies.length} Pedido(s)
              </Button>
            </div>
          </Card>
        </div>
      )}
    </div>
  );
};

export default ScheduledConfirmation;

import React, { useState, useEffect } from 'react';
import { Company, Employee, Order, Product, CompanyProductSetting, RecurringOrderConfig } from './types';
import Sidebar from './components/Sidebar';
import CompanyManagement from './components/CompanyProfile';
import EmployeeManagement from './components/EmployeeManagement';
import { BuildingStorefrontIcon, UsersIcon, ClipboardDocumentListIcon, TagIcon, ShoppingBagIcon, CheckCircleIcon } from './components/Icons';
import LoginPage from './components/LoginPage';
import OrderManagement from './components/OrderManagement';
import ProductManagement from './components/ProductManagement';
import CompanyDetailView from './components/CompanyDetailView';
import ScheduledConfirmation from './components/ScheduledConfirmation';

type View = 'companies' | 'employees' | 'orders' | 'door-sales' | 'products' | 'scheduled-confirmation';

const loadFromLocalStorage = <T,>(key: string, defaultValue: T): T => {
    try {
        const storedValue = localStorage.getItem(key);
        if (storedValue) return JSON.parse(storedValue);
    } catch (error) { console.error(`Error loading ${key}`, error); }
    return defaultValue;
};

const saveToLocalStorage = <T,>(key: string, value: T) => {
    try { localStorage.setItem(key, JSON.stringify(value)); } catch (error) { console.error(`Error saving ${key}`, error); }
};

const initialCompanies: Company[] = [
    {
      id: '1',
      name: 'Padaria Doce Pão',
      cnpj: '12.345.678/0001-99',
      address: 'Rua das Flores, 123, São Paulo - SP',
      cep: '01234-567',
      phone: '(11) 98765-4321',
      logoUrl: 'https://picsum.photos/seed/bakerylogo/200',
      doorSale: true,
      orders: [],
      productSettings: [
        { productId: 'prod-1', buys: true, price: 0.75 },
        { productId: 'prod-2', buys: true, price: 5.50 }
      ]
    }
];

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);
  const [currentView, setCurrentView] = useState<View>('companies');
  const [companies, setCompanies] = useState<Company[]>(() => loadFromLocalStorage('companies', initialCompanies));
  const [employees, setEmployees] = useState<Employee[]>(() => loadFromLocalStorage('employees', []));
  const [products, setProducts] = useState<Product[]>(() => loadFromLocalStorage('products', []));
  const [selectedCompanyId, setSelectedCompanyId] = useState<string | null>(null);
  const [viewingCompanyId, setViewingCompanyId] = useState<string | null>(null);

  useEffect(() => { saveToLocalStorage('companies', companies); }, [companies]);
  useEffect(() => { saveToLocalStorage('employees', employees); }, [employees]);
  useEffect(() => { saveToLocalStorage('products', products); }, [products]);

  // Lógica de Geração Automática de Pedidos Recorrentes (como PENDENTES) para HOJE
  useEffect(() => {
    if (isAuthenticated) {
      const todayStr = new Date().toISOString().split('T')[0];
      const todayDay = new Date().getDay(); // 0 (Dom) a 6 (Sab)

      setCompanies(prevCompanies => prevCompanies.map(company => {
        if (!company.recurringOrder) return company;

        const { recurrence, items } = company.recurringOrder;

        // Verifica se já existe um pedido (pendente ou confirmado) para hoje
        const alreadyGeneratedToday = company.orders.some(o => o.date === todayStr);
        if (alreadyGeneratedToday) return company;

        let shouldGenerate = false;
        switch (recurrence.type) {
          case 'daily': 
            shouldGenerate = true; 
            break;
          case 'weekdays': 
            shouldGenerate = todayDay >= 1 && todayDay <= 5; 
            break;
          case 'weekly':
            shouldGenerate = true; 
            break;
          default: 
            shouldGenerate = false;
        }

        if (shouldGenerate) {
          const newOrder: Order = {
            id: `auto-${Date.now()}-${company.id}`,
            date: todayStr,
            items: items.map((it, idx) => ({ ...it, id: `item-auto-${idx}-${Date.now()}` })),
            status: 'pending' 
          };
          return {
            ...company,
            orders: [newOrder, ...company.orders]
          };
        }
        return company;
      }));
    }
  }, [isAuthenticated]);

  const handleConfirmOrder = (companyId: string, orderId: string) => {
    setCompanies(prev => prev.map(c => {
      if (c.id === companyId) {
        return {
          ...c,
          orders: c.orders.map(o => o.id === orderId ? { ...o, status: 'confirmed' } : o)
        };
      }
      return c;
    }));
  };

  const handleLaunchBatch = (ordersToLaunch: { companyId: string, order: Omit<Order, 'id'> }[]) => {
    setCompanies(prev => prev.map(c => {
      const orderData = ordersToLaunch.find(ol => ol.companyId === c.id);
      if (orderData) {
        const newOrder: Order = {
          ...orderData.order,
          id: `manual-auto-${Date.now()}-${c.id}`
        };
        return {
          ...c,
          orders: [newOrder, ...c.orders]
        };
      }
      return c;
    }));
  };

  const handleUpdateRecurringOrder = (companyId: string, config: RecurringOrderConfig) => {
    setCompanies(prev => prev.map(c => c.id === companyId ? { ...c, recurringOrder: config } : c));
  };

  const handleLogin = (user: string, pass: string): boolean => {
    if (user === 'admin' && pass === 'admin') {
      setIsAuthenticated(true);
      return true;
    }
    return false;
  };

  const handleLogout = () => { setIsAuthenticated(false); setViewingCompanyId(null); };

  const handleSetCurrentView = (view: View) => {
    setCurrentView(view);
    setViewingCompanyId(null);
    const filtered = view === 'orders' ? companies.filter(c => !c.doorSale) : view === 'door-sales' ? companies.filter(c => c.doorSale) : companies;
    setSelectedCompanyId(filtered.length > 0 ? filtered[0].id : null);
  }

  const handleAddCompany = (newCompanyData: Omit<Company, 'id' | 'orders'>) => {
    const newCompany: Company = { ...newCompanyData, id: Date.now().toString(), orders: [], productSettings: [] };
    setCompanies(prev => [...prev, newCompany]);
  };

  const handleUpdateCompany = (updatedCompany: Company) => {
    setCompanies(prev => prev.map(c => c.id === updatedCompany.id ? updatedCompany : c));
  };

  const handleDeleteCompany = (companyId: string) => {
    const remaining = companies.filter(c => c.id !== companyId);
    setCompanies(remaining);
    if (selectedCompanyId === companyId) setSelectedCompanyId(remaining.length > 0 ? remaining[0].id : null);
  };

  const handleAddOrder = (newOrderData: Omit<Order, 'id'>) => {
    if (!selectedCompanyId) return;
    setCompanies(prev => prev.map(c => {
      if (c.id === selectedCompanyId) {
        const newOrder: Order = { ...newOrderData, id: `order-${Date.now()}`, status: 'confirmed' };
        return { ...c, orders: [newOrder, ...c.orders].sort((a, b) => b.date.localeCompare(a.date)) };
      }
      return c;
    }));
  };

  const handleDeleteOrder = (orderId: string) => {
    if (!selectedCompanyId) return;
    setCompanies(prev => prev.map(c => c.id === selectedCompanyId ? { ...c, orders: c.orders.filter(o => o.id !== orderId) } : c));
  };

  const handleUpdateOrderSignature = (orderId: string, signature: string) => {
    if (!selectedCompanyId) return;
    setCompanies(prev => prev.map(c => c.id === selectedCompanyId ? { ...c, orders: c.orders.map(o => o.id === orderId ? { ...o, signature } : o) } : c));
  };

  const renderContent = () => {
    const selectedCompany = companies.find(c => c.id === selectedCompanyId) || null;
    const companyToView = companies.find(c => c.id === viewingCompanyId);

    if (currentView === 'companies' && companyToView) {
      return <CompanyDetailView company={companyToView} products={products} onUpdate={handleUpdateCompany} onUpdateProductSettings={(id, s) => setCompanies(prev => prev.map(c => c.id === id ? { ...c, productSettings: s } : c))} onBack={() => setViewingCompanyId(null)} />
    }

    switch (currentView) {
      case 'companies': return <CompanyManagement companies={companies} onAdd={handleAddCompany} onUpdate={handleUpdateCompany} onDelete={handleDeleteCompany} onViewCompany={setViewingCompanyId} />;
      case 'employees': return <EmployeeManagement employees={employees} onAddEmployee={(e) => setEmployees(prev => [...prev, { ...e, id: `emp-${Date.now()}`, status: 'Ativo' }])} onDeleteEmployee={(id) => setEmployees(prev => prev.filter(e => e.id !== id))} onUpdateEmployeeStatus={(id, s) => setEmployees(prev => prev.map(e => e.id === id ? { ...e, status: s } : e))} />;
      case 'scheduled-confirmation': return <ScheduledConfirmation companies={companies} onConfirmOrder={handleConfirmOrder} onDeleteOrder={(cid, oid) => { setSelectedCompanyId(cid); handleDeleteOrder(oid); }} onLaunchBatch={handleLaunchBatch} />;
      case 'orders': return <OrderManagement companies={companies.filter(c => !c.doorSale)} selectedCompany={selectedCompany} products={products} onSelectCompany={setSelectedCompanyId} onAddOrder={handleAddOrder} onDeleteOrder={handleDeleteOrder} onUpdateOrderSignature={handleUpdateOrderSignature} onUpdateRecurringOrder={handleUpdateRecurringOrder} isDoorSaleMode={false} />;
      case 'door-sales': return <OrderManagement companies={companies.filter(c => c.doorSale)} selectedCompany={selectedCompany} products={products} onSelectCompany={setSelectedCompanyId} onAddOrder={handleAddOrder} onDeleteOrder={handleDeleteOrder} onUpdateOrderSignature={handleUpdateOrderSignature} isDoorSaleMode={true} />;
      case 'products': return <ProductManagement products={products} onAdd={(p) => setProducts(prev => [...prev, { ...p, id: `prod-${Date.now()}` }])} onUpdate={(p) => setProducts(prev => prev.map(prod => prod.id === p.id ? p : prod))} onDelete={(id) => setProducts(prev => prev.filter(p => p.id !== id))} />;
      default: return null;
    }
  };

  if (!isAuthenticated) return <LoginPage onLogin={handleLogin} />;

  const headerInfo = {
    companies: { icon: <BuildingStorefrontIcon className="h-8 w-8 text-orange-500" />, title: 'Gerenciamento de Empresas', subtitle: 'Adicione, visualize e edite as informações das suas empresas clientes.' },
    employees: { icon: <UsersIcon className="h-8 w-8 text-orange-500" />, title: 'Gerenciamento de Funcionários', subtitle: 'Gerencie a equipe da Engenho do Pão.' },
    'scheduled-confirmation': { icon: <CheckCircleIcon className="h-8 w-8 text-orange-500" />, title: 'Confirmar pedidos agendados', subtitle: 'Revise e aprove os pedidos gerados automaticamente pelo sistema.' },
    orders: { icon: <ClipboardDocumentListIcon className="h-8 w-8 text-orange-500" />, title: 'Histórico de pedidos', subtitle: 'Acompanhe o registro histórico de pedidos de clientes regulares.' },
    'door-sales': { icon: <ShoppingBagIcon className="h-8 w-8 text-orange-500" />, title: 'Venda na Porta', subtitle: 'Gerencie pedidos específicos de venda na porta.' },
    products: { icon: <TagIcon className="h-8 w-8 text-orange-500" />, title: 'Gerenciamento de Produtos', subtitle: 'Cadastre e organize os produtos oferecidos pela padaria.' },
  };

  return (
    <div className="flex h-screen bg-orange-50 font-sans">
      <Sidebar currentView={currentView} setCurrentView={handleSetCurrentView} onLogout={handleLogout} />
      <main className="flex-1 p-4 md:p-8 overflow-y-auto">
        {!(currentView === 'companies' && viewingCompanyId) && (
          <header className="mb-8">
              <div className="flex items-center gap-4">
                  {headerInfo[currentView].icon}
                  <h1 className="text-3xl font-bold text-amber-800">{headerInfo[currentView].title}</h1>
              </div>
              <p className="text-amber-600 mt-1">{headerInfo[currentView].subtitle}</p>
          </header>
        )}
        {renderContent()}
      </main>
    </div>
  );
};

export default App;

