import React, { useState, useEffect } from 'react';
import { Company, Order, OrderItem } from '../types';
import Card from './common/Card';
import Button from './common/Button';
import { CheckCircleIcon, TrashIcon, CalendarDaysIcon, RocketLaunchIcon, XMarkIcon, PencilIcon, CheckIcon } from './Icons';

interface DraftOrder {
  companyId: string;
  companyName: string;
  logoUrl: string;
  recurrenceType: string;
  items: Omit<OrderItem, 'id'>[];
  selected: boolean;
  isEditing: boolean;
}

interface ScheduledConfirmationProps {
  companies: Company[];
  onConfirmOrder: (companyId: string, orderId: string) => void;
  onDeleteOrder: (companyId: string, orderId: string) => void;
  onLaunchBatch: (orders: { companyId: string, order: Omit<Order, 'id'> }[]) => void;
}

const ScheduledConfirmation: React.FC<ScheduledConfirmationProps> = ({ companies, onConfirmOrder, onDeleteOrder, onLaunchBatch }) => {
  const [isOverviewOpen, setIsOverviewOpen] = useState(false);
  const [draftOrders, setDraftOrders] = useState<DraftOrder[]>([]);

  const pendingOrders = companies.flatMap(c => 
    c.orders
      .filter(o => o.status === 'pending')
      .map(o => ({ company: c, order: o }))
  );

  const getTomorrowStr = () => {
    const tomorrow = new Date();
    tomorrow.setDate(tomorrow.getDate() + 1);
    return tomorrow.toISOString().split('T')[0];
  };

  const tomorrowStr = getTomorrowStr();

  const handleOpenOverview = () => {
    const tomorrow = new Date();
    tomorrow.setDate(tomorrow.getDate() + 1);
    const tDay = tomorrow.getDay();
    const tStr = tomorrow.toISOString().split('T')[0];

    const initialDrafts: DraftOrder[] = companies
      .filter(c => {
        if (!c.recurringOrder) return false;
        const alreadyHasTomorrow = c.orders.some(o => o.date === tStr);
        if (alreadyHasTomorrow) return false;

        const { type, daysOfWeek } = c.recurringOrder.recurrence;
        if (daysOfWeek) return daysOfWeek.includes(tDay);
        if (type === 'daily') return true;
        if (type === 'weekdays') return tDay >= 1 && tDay <= 5;
        return false;
      })
      .map(c => ({
        companyId: c.id,
        companyName: c.name,
        logoUrl: c.logoUrl,
        recurrenceType: c.recurringOrder!.recurrence.type,
        items: c.recurringOrder!.items.map(it => ({ ...it })),
        selected: true,
        isEditing: false
      }));

    setDraftOrders(initialDrafts);
    if (initialDrafts.length > 0) {
      setIsOverviewOpen(true);
    } else {
      alert("Nenhum pedido agendado para amanhã.");
    }
  };

  const handleRemoveDraft = (companyId: string) => {
    setDraftOrders(prev => prev.filter(d => d.companyId !== companyId));
  };

  const toggleEditDraft = (companyId: string) => {
    setDraftOrders(prev => prev.map(d => 
      d.companyId === companyId ? { ...d, isEditing: !d.isEditing } : d
    ));
  };

  const updateDraftItemQuantity = (companyId: string, itemIndex: number, quantity: number) => {
    setDraftOrders(prev => prev.map(d => {
      if (d.companyId === companyId) {
        const newItems = [...d.items];
        newItems[itemIndex].quantity = Math.max(1, quantity);
        return { ...d, items: newItems };
      }
      return d;
    }));
  };

  const toggleSelection = (companyId: string) => {
    setDraftOrders(prev => prev.map(d => 
      d.companyId === companyId ? { ...d, selected: !d.selected } : d
    ));
  };

  const handleConfirmLaunch = () => {
    const selectedDrafts = draftOrders.filter(d => d.selected);
    const ordersToLaunch = selectedDrafts.map(d => ({
      companyId: d.companyId,
      order: {
        date: tomorrowStr,
        items: d.items.map((it, idx) => ({ ...it, id: `item-auto-${idx}-${Date.now()}` })),
        status: 'pending' as const
      }
    }));

    onLaunchBatch(ordersToLaunch);
    setIsOverviewOpen(false);
  };

  const selectedCount = draftOrders.filter(d => d.selected).length;

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Action Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 bg-white p-6 rounded-xl shadow-sm border border-orange-100">
        <div>
          <h2 className="text-lg font-bold text-amber-800">Ações de Agendamento</h2>
