import React, { useState, useEffect } from 'react';
import { Company, Order, OrderItem } from '../types';
import Card from './common/Card';
import Button from './common/Button';
import { CheckCircleIcon, TrashIcon, CalendarDaysIcon, RocketLaunchIcon, XMarkIcon, PencilIcon, CheckIcon } from './Icons';

interface DraftOrder {
  companyId: string;
  companyName: string;
  logoUrl: string;
  recurrenceType: string;
  items: Omit<OrderItem, 'id'>[];
  selected: boolean;
  isEditing: boolean;
}

interface ScheduledConfirmationProps {
  companies: Company[];
  onConfirmOrder: (companyId: string, orderId: string) => void;
  onDeleteOrder: (companyId: string, orderId: string) => void;
  onLaunchBatch: (orders: { companyId: string, order: Omit<Order, 'id'> }[]) => void;
}

const ScheduledConfirmation: React.FC<ScheduledConfirmationProps> = ({ companies, onConfirmOrder, onDeleteOrder, onLaunchBatch }) => {
  const [isOverviewOpen, setIsOverviewOpen] = useState(false);
  const [draftOrders, setDraftOrders] = useState<DraftOrder[]>([]);

  const pendingOrders = companies.flatMap(c => 
    c.orders
      .filter(o => o.status === 'pending')
      .map(o => ({ company: c, order: o }))
  ).sort((a, b) => b.order.date.localeCompare(a.order.date));

  // Função para pegar string YYYY-MM-DD local
  const getLocalDateStr = (date: Date) => {
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
  };

  const getTomorrowStr = () => {
    const tomorrow = new Date();
    tomorrow.setDate(tomorrow.getDate() + 1);
    return getLocalDateStr(tomorrow);
  };

  const tomorrowStr = getTomorrowStr();

  const handleOpenOverview = () => {
    const tomorrow = new Date();
    tomorrow.setDate(tomorrow.getDate() + 1);
    const tDay = tomorrow.getDay();
    const tStr = getLocalDateStr(tomorrow);

    const initialDrafts: DraftOrder[] = companies
      .filter(c => {
        if (!c.recurringOrder || !c.recurringOrder.recurrence) return false;

        // Evita duplicar se já existir pedido lançado para amanhã
        const alreadyHasTomorrow = c.orders.some(o => o.date === tStr);
        if (alreadyHasTomorrow) return false;

        const { type, daysOfWeek } = c.recurringOrder.recurrence;

        // Lógica de verificação de dia
        if (daysOfWeek && daysOfWeek.length > 0) {
          return daysOfWeek.includes(tDay);
        }

        // Fallbacks baseados no tipo
        if (type === 'daily') return true;
        if (type === 'weekdays') return tDay >= 1 && tDay <= 5;
        if (type === 'weekly' || type === 'custom') return true; // Na dúvida, permite lançar se não houver dias específicos

        return false;
      })
      .map(c => ({
        companyId: c.id,
        companyName: c.name,
        logoUrl: c.logoUrl,
        recurrenceType: c.recurringOrder!.recurrence.type,
        items: c.recurringOrder!.items.map(it => ({ ...it })),
        selected: true,
        isEditing: false
      }));

    if (initialDrafts.length > 0) {
      setDraftOrders(initialDrafts);
      setIsOverviewOpen(true);
    } else {
      alert("Não há novos pedidos agendados para amanhã ou todos já foram lançados.");
    }
  };

  const handleRemoveDraft = (companyId: string) => {
    setDraftOrders(prev => prev.filter(d => d.companyId !== companyId));
  };

  const toggleEditDraft = (companyId: string) => {
    setDraftOrders(prev => prev.map(d => 
      d.companyId === companyId ? { ...d, isEditing: !d.isEditing } : d
    ));
  };

  const updateDraftItemQuantity = (companyId: string, itemIndex: number, quantity: number) => {
    setDraftOrders(prev => prev.map(d => {
      if (d.companyId === companyId) {
        const newItems = [...d.items];
        newItems[itemIndex].quantity = isNaN(quantity) || quantity < 1 ? 1 : quantity;
        return { ...d, items: newItems };
      }
      return d;
    }));
  };

  const toggleSelection = (companyId: string) => {
    setDraftOrders(prev => prev.map(d => 
      d.companyId === companyId ? { ...d, selected: !d.selected } : d
    ));
  };

  const handleConfirmLaunch = () => {
    const selectedDrafts = draftOrders.filter(d => d.selected);
    const ordersToLaunch = selectedDrafts.map(d => ({
      companyId: d.companyId,
      order: {
        date: tomorrowStr,
        items: d.items.map((it, idx) => ({ ...it, id: `item-auto-${idx}-${Date.now()}` })),
        status: 'pending' as const
      }
    }));

    onLaunchBatch(ordersToLaunch);
    setIsOverviewOpen(false);
    setDraftOrders([]);
  };

  const selectedCount = draftOrders.filter(d => d.selected).length;

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Action Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 bg-white p-6 rounded-xl shadow-sm border border-orange-100">
        <div>
          <h2 className="text-lg font-bold text-amber-800">Ações de Agendamento</h2>
          <p className="text-sm text-amber-600">Prepare a produção lançando os pedidos de amanhã ({new Date(tomorrowStr + 'T12:00:00Z').toLocaleDateString('pt-BR', {day:'2-digit', month:'short'})}).</p>
        </div>
        <Button 
          onClick={handleOpenOverview} 
          className="w-full sm:w-auto shadow-md"
        >
          <RocketLaunchIcon className="h-5 w-5 mr-2" />
          Lançar pedidos de amanhã
        </Button>
      </div>

      {/* List of Pending Orders */}
      <div className="space-y-4">
        <h3 className="text-xs font-bold text-amber-500 uppercase tracking-[0.2em] ml-1">Pedidos Aguardando Confirmação</h3>
        {pendingOrders.length === 0 ? (
          <Card className="text-center p-12 bg-white/50 border border-dashed border-orange-200 shadow-none">
            <CheckCircleIcon className="mx-auto h-12 w-12 text-orange-200" />
            <p className="mt-4 text-sm text-amber-600 font-medium">Todos os pedidos agendados foram confirmados.</p>
          </Card>
        ) : (
          pendingOrders.map(({ company, order }) => (
            <Card key={order.id} className="p-0 border border-orange-100 hover:border-orange-200 transition-all">
              <div className="p-5">
                <div className="flex flex-col md:flex-row justify-between gap-6">
                  <div className="flex-1 space-y-4">
                    <div className="flex items-center gap-3">
                      <img src={company.logoUrl} alt={company.name} className="h-10 w-10 rounded-full border border-orange-50" />
                      <div>
                        <div className="flex items-center gap-2">
                            <h3 className="text-base font-bold text-amber-900">{company.name}</h3>
                            <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full uppercase tracking-wider ${order.date > getLocalDateStr(new Date()) ? 'bg-blue-50 text-blue-600' : 'bg-orange-50 text-orange-600'}`}>
                                {order.date > getLocalDateStr(new Date()) ? 'Antecipado' : 'Hoje'}
                            </span>
                        </div>
                        <p className="text-xs text-amber-500 flex items-center gap-1">
                          <CalendarDaysIcon className="h-3 w-3" />
                          {new Date(order.date + 'T12:00:00Z').toLocaleDateString('pt-BR', { day: '2-digit', month: 'short', year: 'numeric' })}
                        </p>
                      </div>
                    </div>
                    <div className="bg-orange-50/30 rounded-lg p-4 border border-orange-100/50">
                      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-2">
                        {order.items.map(item => (
                          <div key={item.id} className="text-xs flex items-center justify-between bg-white/60 p-2 rounded border border-orange-50">
                            <span className="text-gray-600 truncate">{item.productName}</span>
                            <span className="font-bold text-amber-800 ml-2">{item.quantity}</span>
                          </div>
                        ))}
                      </div>
                    </div>
                  </div>
                  <div className="flex flex-row md:flex-col justify-end gap-2">
                    <Button onClick={() => onConfirmOrder(company.id, order.id)} className="h-10 text-xs px-4">
                      Confirmar
                    </Button>
                    <button 
                        onClick={() => onDeleteOrder(company.id, order.id)}
                        className="h-10 px-4 text-xs font-bold text-red-400 hover:text-red-600 transition-colors"
                    >
                      Remover
                    </button>
                  </div>
                </div>
              </div>
            </Card>
          ))
        )}
      </div>

      {/* Tomorrow Overview Modal */}
      {isOverviewOpen && (
        <div className="fixed inset-0 bg-amber-900/20 z-50 flex items-center justify-center p-4 backdrop-blur-md animate-fade-in">
          <Card className="w-full max-w-2xl max-h-[85vh] flex flex-col shadow-2xl border-none">
            <div className="px-8 py-6 border-b border-orange-50 flex justify-between items-center">
              <div>
                <h3 className="text-xl font-bold text-amber-900">Pedidos para Amanhã</h3>
                <p className="text-xs font-medium text-amber-500 mt-1 uppercase tracking-widest">
                  {new Date(tomorrowStr + 'T12:00:00Z').toLocaleDateString('pt-BR', { day: '2-digit', month: 'long' })}
                </p>
              </div>
              <button onClick={() => setIsOverviewOpen(false)} className="p-2 hover:bg-orange-50 rounded-full transition-colors text-amber-300 hover:text-amber-500">
                <XMarkIcon className="h-6 w-6" />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto">
              <div className="divide-y divide-orange-50">
                {draftOrders.map((draft) => (
                  <div 
                    key={draft.companyId} 
                    className={`group px-8 py-5 transition-all flex items-start gap-4 ${
                      draft.selected ? 'bg-orange-50/30' : 'opacity-40 grayscale'
                    }`}
                  >
                    <div 
                      onClick={() => toggleSelection(draft.companyId)}
                      className={`mt-1 h-5 w-5 rounded-full border-2 flex items-center justify-center cursor-pointer transition-all ${
                        draft.selected ? 'bg-orange-500 border-orange-500 text-white' : 'border-amber-200 bg-white'
                      }`}
                    >
                        {draft.selected && <CheckIcon className="h-3 w-3 stroke-[3]" />}
                    </div>

                    <div className="flex-1 min-w-0">
                      <div className="flex items-center justify-between mb-1">
                        <div className="flex items-center gap-2">
                           <span className="font-bold text-amber-900 text-sm">{draft.companyName}</span>
                           <span className="text-[9px] font-bold text-amber-400 uppercase tracking-tighter">({draft.recurrenceType})</span>
                        </div>

                        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                          <button 
                            onClick={() => toggleEditDraft(draft.companyId)}
                            className={`p-1.5 rounded hover:bg-white shadow-sm transition-all ${draft.isEditing ? 'text-green-500' : 'text-blue-400'}`}
                          >
                            {draft.isEditing ? <CheckIcon className="h-4 w-4" /> : <PencilIcon className="h-4 w-4" />}
                          </button>
                          <button 
                            onClick={() => handleRemoveDraft(draft.companyId)}
                            className="p-1.5 rounded hover:bg-white shadow-sm text-red-300 hover:text-red-500 transition-all"
                          >
                            <TrashIcon className="h-4 w-4" />
                          </button>
                        </div>
                      </div>

                      {draft.isEditing ? (
                        <div className="mt-3 space-y-2 animate-slide-up bg-white p-3 rounded border border-orange-100">
                          {draft.items.map((item, i) => (
                            <div key={i} className="flex items-center justify-between gap-2">
