import React, { useState, useEffect } from 'react';
import { Company, Employee, Order, Product, CompanyProductSetting, RecurringOrderConfig } from './types';
import Sidebar from './components/Sidebar';
import CompanyManagement from './components/CompanyProfile';
import EmployeeManagement from './components/EmployeeManagement';
import { BuildingStorefrontIcon, UsersIcon, ClipboardDocumentListIcon, TagIcon, ShoppingBagIcon, CheckCircleIcon } from './components/Icons';
import LoginPage from './components/LoginPage';
import OrderManagement from './components/OrderManagement';
import ProductManagement from './components/ProductManagement';
import CompanyDetailView from './components/CompanyDetailView';
import ScheduledConfirmation from './components/ScheduledConfirmation';

type View = 'companies' | 'employees' | 'orders' | 'door-sales' | 'products' | 'scheduled-confirmation';

const loadFromLocalStorage = <T,>(key: string, defaultValue: T): T => {
    try {
        const storedValue = localStorage.getItem(key);
        if (storedValue) return JSON.parse(storedValue);
    } catch (error) { console.error(`Error loading ${key}`, error); }
    return defaultValue;
};

const saveToLocalStorage = <T,>(key: string, value: T) => {
    try { localStorage.setItem(key, JSON.stringify(value)); } catch (error) { console.error(`Error saving ${key}`, error); }
};

const initialCompanies: Company[] = [
    {
      id: '1',
      name: 'Padaria Doce Pão',
      cnpj: '12.345.678/0001-99',
      address: 'Rua das Flores, 123, São Paulo - SP',
      cep: '01234-567',
      phone: '(11) 98765-4321',
      logoUrl: 'https://picsum.photos/seed/bakerylogo/200',
      doorSale: true,
      orders: [],
      productSettings: [
        { productId: 'prod-1', buys: true, price: 0.75 },
        { productId: 'prod-2', buys: true, price: 5.50 }
      ]
    }
];

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);
  const [currentView, setCurrentView] = useState<View>('companies');
  const [companies, setCompanies] = useState<Company[]>(() => loadFromLocalStorage('companies', initialCompanies));
  const [employees, setEmployees] = useState<Employee[]>(() => loadFromLocalStorage('employees', []));
  const [products, setProducts] = useState<Product[]>(() => loadFromLocalStorage('products', []));
  const [selectedCompanyId, setSelectedCompanyId] = useState<string | null>(null);
  const [viewingCompanyId, setViewingCompanyId] = useState<string | null>(null);

  useEffect(() => { saveToLocalStorage('companies', companies); }, [companies]);
  useEffect(() => { saveToLocalStorage('employees', employees); }, [employees]);
  useEffect(() => { saveToLocalStorage('products', products); }, [products]);

  // Lógica de Geração Automática de Pedidos Recorrentes
  useEffect(() => {
    if (isAuthenticated) {
      const today = new Date();
      const todayStr = today.toISOString().split('T')[0];
      const todayDay = today.getDay();

      setCompanies(prevCompanies => prevCompanies.map(company => {
        if (!company.recurringOrder) return company;

        const { recurrence, items } = company.recurringOrder;
        const alreadyGeneratedToday = company.orders.some(o => o.date === todayStr);
        if (alreadyGeneratedToday) return company;

        let shouldGenerate = false;
        if (recurrence.daysOfWeek) {
          shouldGenerate = recurrence.daysOfWeek.includes(todayDay);
        } else {
          switch (recurrence.type) {
            case 'daily': shouldGenerate = true; break;
            case 'weekdays': shouldGenerate = todayDay >= 1 && todayDay <= 5; break;
            case 'weekly': shouldGenerate = true; break;
            default: shouldGenerate = false;
          }
        }

        if (shouldGenerate) {
          const newOrder: Order = {
            id: `auto-${Date.now()}-${company.id}`,
            date: todayStr,
            items: items.map((it, idx) => ({ ...it, id: `item-auto-${idx}-${Date.now()}` })),
            status: 'pending' 
          };
          return {
            ...company,
            orders: [newOrder, ...company.orders]
          };
        }
        return company;
      }));
    }
  }, [isAuthenticated]);

  const handleConfirmOrder = (companyId: string, orderId: string) => {
    setCompanies(prev => prev.map(c => {
      if (c.id === companyId) {
        return {
          ...c,
          orders: c.orders.map(o => o.id === orderId ? { ...o, status: 'confirmed' } : o)
        };
      }
      return c;
    }));
  };

  const handleLaunchBatch = (ordersToLaunch: { companyId: string, order: Omit<Order, 'id'> }[]) => {
    setCompanies(prev => prev.map(c => {
      const orderData = ordersToLaunch.find(ol => ol.companyId === c.id);
      if (orderData) {
        const newOrder: Order = {
          ...orderData.order,
          id: `manual-batch-${Date.now()}-${c.id}`
        };
        return {
          ...c,
          orders: [newOrder, ...c.orders]
        };
      }
      return c;
    }));
  };

  const handleUpdateRecurringOrder = (companyId: string, config: RecurringOrderConfig) => {
    setCompanies(prev => prev.map(c => c.id === companyId ? { ...c, recurringOrder: config } : c));
  };

  const handleLogin = (user: string, pass: string): boolean => {
    if (user === 'admin' && pass === 'admin') {
      setIsAuthenticated(true);
      return true;
    }
    return false;
  };

  const handleLogout = () => { setIsAuthenticated(false); setViewingCompanyId(null); };

  const handleSetCurrentView = (view: View) => {
    setCurrentView(view);
    setViewingCompanyId(null);

    const filtered = view === 'door-sales' 
      ? companies.filter(c => c.doorSale) 
      : companies; 

    setSelectedCompanyId(filtered.length > 0 ? filtered[0].id : null);
  }

  const handleAddCompany = (newCompanyData: Omit<Company, 'id' | 'orders'>) => {
    const newCompany: Company = { ...newCompanyData, id: Date.now().toString(), orders: [], productSettings: [] };
    setCompanies(prev => [...prev, newCompany]);
  };

  const handleUpdateCompany = (updatedCompany: Company) => {
    setCompanies(prev => prev.map(c => c.id === updatedCompany.id ? updatedCompany : c));
  };

  const handleDeleteCompany = (companyId: string) => {
    const remaining = companies.filter(c => c.id !== companyId);
    setCompanies(remaining);
    if (selectedCompanyId === companyId) setSelectedCompanyId(remaining.length > 0 ? remaining[0].id : null);
  };

  const handleAddOrder = (newOrderData: Omit<Order, 'id'>, companyId?: string) => {
    const targetId = companyId || selectedCompanyId;
    if (!targetId) return;
    setCompanies(prev => prev.map(c => {
      if (c.id === targetId) {
        // Agora pedidos manuais começam como 'pending' para serem confirmados
        const newOrder: Order = { ...newOrderData, id: `order-manual-${Date.now()}`, status: 'pending' };
        return { ...c, orders: [newOrder, ...c.orders].sort((a, b) => b.date.localeCompare(a.date)) };
      }
      return c;
    }));
  };

  const handleDeleteOrder = (orderId: string, companyId?: string) => {
    const targetId = companyId || selectedCompanyId;
    if (!targetId) return;
    setCompanies(prev => prev.map(c => c.id === targetId ? { ...c, orders: c.orders.filter(o => o.id !== orderId) } : c));
  };

  const handleUpdateOrderSignature = (orderId: string, signature: string) => {
    if (!selectedCompanyId) return;
    setCompanies(prev => prev.map(c => c.id === selectedCompanyId ? { ...c, orders: c.orders.map(o => o.id === orderId ? { ...o, signature } : o) } : c));
  };

  const renderContent = () => {
    const selectedCompany = companies.find(c => c.id === selectedCompanyId) || null;
    const companyToView = companies.find(c => c.id === viewingCompanyId);

    if (currentView === 'companies' && companyToView) {
      return <CompanyDetailView company={companyToView} products={products} onUpdate={handleUpdateCompany} onUpdateProductSettings={(id, s) => setCompanies(prev => prev.map(c => c.id === id ? { ...c, productSettings: s } : c))} onBack={() => setViewingCompanyId(null)} />
    }

    switch (currentView) {
      case 'companies': return <CompanyManagement companies={companies} onAdd={handleAddCompany} onUpdate={handleUpdateCompany} onDelete={handleDeleteCompany} onViewCompany={setViewingCompanyId} />;
      case 'employees': return <EmployeeManagement employees={employees} onAddEmployee={(e) => setEmployees(prev => [...prev, { ...e, id: `emp-${Date.now()}`, status: 'Ativo' }])} onDeleteEmployee={(id) => setEmployees(prev => prev.filter(e => e.id !== id))} onUpdateEmployeeStatus={(id, s) => setEmployees(prev => prev.map(e => e.id === id ? { ...e, status: s } : e))} />;
      case 'scheduled-confirmation': return <ScheduledConfirmation companies={companies} products={products} onConfirmOrder={handleConfirmOrder} onDeleteOrder={handleDeleteOrder} onLaunchBatch={handleLaunchBatch} onAddManualOrder={handleAddOrder} />;
      case 'orders': 
        return <OrderManagement companies={companies} selectedCompany={selectedCompany} products={products} onSelectCompany={setSelectedCompanyId} onAddOrder={handleAddOrder} onDeleteOrder={(id) => handleDeleteOrder(id)} onUpdateOrderSignature={handleUpdateOrderSignature} onUpdateRecurringOrder={handleUpdateRecurringOrder} isDoorSaleMode={false} />;
      case 'door-sales': 
        return <OrderManagement companies={companies.filter(c => c.doorSale)} selectedCompany={selectedCompany} products={products} onSelectCompany={setSelectedCompanyId} onAddOrder={handleAddOrder} onDeleteOrder={(id) => handleDeleteOrder(id)} onUpdateOrderSignature={handleUpdateOrderSignature} isDoorSaleMode={true} />;
      case 'products': return <ProductManagement products={products} onAdd={(p) => setProducts(prev => [...prev, { ...p, id: `prod-${Date.now()}` }])} onUpdate={(p) => setProducts(prev => prev.map(prod => prod.id === p.id ? p : prod))} onDelete={(id) => setProducts(prev => prev.filter(p => p.id !== id))} />;
      default: return null;
    }
  };

  if (!isAuthenticated) return <LoginPage onLogin={handleLogin} />;

  const headerInfo = {
    companies: { icon: <BuildingStorefrontIcon className="h-8 w-8 text-orange-500" />, title: 'Gerenciamento de Empresas', subtitle: 'Adicione, visualize e edite as informações das suas empresas clientes.' },
    employees: { icon: <UsersIcon className="h-8 w-8 text-orange-500" />, title: 'Gerenciamento de Funcionários', subtitle: 'Gerencie a equipe da Engenho do Pão.' },
    'scheduled-confirmation': { icon: <CheckCircleIcon className="h-8 w-8 text-orange-500" />, title: 'Fila de Produção & Confirmação', subtitle: 'Gerencie todos os pedidos aguardando confirmação (agendados e manuais).' },
    orders: { icon: <ClipboardDocumentListIcon className="h-8 w-8 text-orange-500" />, title: 'Histórico de pedidos', subtitle: 'Acompanhe o registro histórico de pedidos de todos os clientes.' },
    'door-sales': { icon: <ShoppingBagIcon className="h-8 w-8 text-orange-500" />, title: 'Venda na Porta', subtitle: 'Gerencie pedidos específicos de venda na porta.' },
    products: { icon: <TagIcon className="h-8 w-8 text-orange-500" />, title: 'Gerenciamento de Produtos', subtitle: 'Cadastre e organize os produtos oferecidos pela padaria.' },
  };

  return (
    <div className="flex h-screen bg-orange-50 font-sans">
      <Sidebar currentView={currentView} setCurrentView={handleSetCurrentView} onLogout={handleLogout} />
      <main className="flex-1 p-4 md:p-8 overflow-y-auto">
        {!(currentView === 'companies' && viewingCompanyId) && (
          <header className="mb-8">
              <div className="flex items-center gap-4">
                  {headerInfo[currentView].icon}
                  <h1 className="text-3xl font-bold text-amber-800">{headerInfo[currentView].title}</h1>
              </div>
              <p className="text-amber-600 mt-1">{headerInfo[currentView].subtitle}</p>
          </header>
        )}
        {renderContent()}
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Company, Order, OrderItem, Product } from '../types';
import Card from './common/Card';
import Button from './common/Button';
import Input from './common/Input';
import { CheckCircleIcon, TrashIcon, CalendarDaysIcon, RocketLaunchIcon, XMarkIcon, PencilIcon, CheckIcon, PlusIcon } from './Icons';

interface DraftOrder {
  companyId: string;
  companyName: string;
  logoUrl: string;
  recurrenceType: string;
  items: Omit<OrderItem, 'id'>[];
  selected: boolean;
  isEditing: boolean;
}

// Modal for manual order creation
const ManualOrderModal = ({ companies, products, onSave, onClose }: { 
  companies: Company[], 
  products: Product[], 
  onSave: (order: Omit<Order, 'id'>, companyId: string) => void, 
  onClose: () => void 
}) => {
  const [selectedCompanyId, setSelectedCompanyId] = useState('');
  const [orderDate, setOrderDate] = useState(new Date().toISOString().split('T')[0]);
  const [items, setItems] = useState<Omit<OrderItem, 'id'>[]>([{ productName: '', quantity: 1 }]);

  const handleItemChange = (index: number, field: 'productName' | 'quantity', value: string | number) => {
    const newItems = [...items];
    if (field === 'quantity') {
      newItems[index][field] = Number(value) < 1 ? 1 : Number(value);
    } else {
      newItems[index][field] = value as string;
    }
    setItems(newItems);
  };

  const addItem = () => setItems([...items, { productName: '', quantity: 1 }]);
  const removeItem = (index: number) => setItems(items.filter((_, i) => i !== index));

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedCompanyId) { alert('Selecione uma empresa.'); return; }
    const validItems = items.filter(it => it.productName !== '');
    if (validItems.length === 0) { alert('Adicione pelo menos um produto.'); return; }

    onSave({
      date: orderDate,
      items: validItems as any,
      status: 'pending'
    }, selectedCompanyId);
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-amber-900/40 z-50 flex items-center justify-center p-4 backdrop-blur-sm animate-fade-in">
      <Card className="w-full max-w-lg shadow-2xl">
        <div className="p-6 border-b border-orange-50 flex justify-between items-center">
          <h3 className="text-lg font-bold text-amber-900">Novo Pedido Manual</h3>
          <button onClick={onClose} className="text-amber-400 hover:text-amber-600 transition-colors">
            <XMarkIcon className="h-6 w-6" />
          </button>
        </div>
        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          <div>
            <label className="block text-xs font-bold text-amber-600 uppercase mb-1">Empresa</label>
            <select 
              value={selectedCompanyId} 
              onChange={e => setSelectedCompanyId(e.target.value)}
              required
              className="w-full px-4 py-2 bg-white border border-orange-100 rounded-lg focus:ring-2 focus:ring-orange-500 outline-none text-sm"
            >
              <option value="">Selecione a empresa...</option>
              {companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-xs font-bold text-amber-600 uppercase mb-1">Data de Entrega</label>
            <Input label="" type="date" value={orderDate} onChange={e => setOrderDate(e.target.value)} required />
          </div>
          <div className="space-y-3 pt-2">
            <label className="block text-xs font-bold text-amber-600 uppercase">Produtos</label>
            {items.map((item, idx) => (
              <div key={idx} className="flex gap-2 items-end">
                <div className="flex-1">
                  <select 
                    value={item.productName} 
                    onChange={e => handleItemChange(idx, 'productName', e.target.value)}
                    required
                    className="w-full px-3 py-1.5 bg-orange-50/50 border border-orange-100 rounded-md text-xs"
                  >
                    <option value="">Produto...</option>
                    {products.map(p => <option key={p.id} value={p.name}>{p.name}</option>)}
                  </select>
                </div>
                <div className="w-20">
                  <input 
                    type="number" 
                    min="1" 
                    value={item.quantity} 
                    onChange={e => handleItemChange(idx, 'quantity', e.target.value)} 
                    className="w-full px-3 py-1.5 bg-orange-50/50 border border-orange-100 rounded-md text-xs text-center font-bold"
                  />
                </div>
                <button type="button" onClick={() => removeItem(idx)} className="p-2 text-red-400">
                  <TrashIcon className="h-4 w-4" />
                </button>
              </div>
            ))}
            <button type="button" onClick={addItem} className="text-xs font-bold text-orange-600 flex items-center gap-1 hover:underline">
              <PlusIcon className="h-4 w-4" /> Adicionar mais um
            </button>
          </div>
          <div className="pt-6 flex gap-3">
            <Button type="button" variant="secondary" onClick={onClose} className="flex-1">Cancelar</Button>
            <Button type="submit" className="flex-1">Criar Pedido</Button>
          </div>
        </form>
      </Card>
    </div>
  );
};

interface ScheduledConfirmationProps {
  companies: Company[];
  products: Product[];
  onConfirmOrder: (companyId: string, orderId: string) => void;
  onDeleteOrder: (orderId: string, companyId: string) => void;
  onLaunchBatch: (orders: { companyId: string, order: Omit<Order, 'id'> }[]) => void;
  onAddManualOrder: (order: Omit<Order, 'id'>, companyId: string) => void;
}

const ScheduledConfirmation: React.FC<ScheduledConfirmationProps> = ({ companies, products, onConfirmOrder, onDeleteOrder, onLaunchBatch, onAddManualOrder }) => {
  const [isOverviewOpen, setIsOverviewOpen] = useState(false);
  const [isManualModalOpen, setIsManualModalOpen] = useState(false);
  const [draftOrders, setDraftOrders] = useState<DraftOrder[]>([]);

  const pendingOrders = companies.flatMap(c => 
    c.orders
      .filter(o => o.status === 'pending')
      .map(o => ({ company: c, order: o }))
  ).sort((a, b) => a.order.date.localeCompare(b.order.date));

  const getLocalDateStr = (date: Date) => {
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
  };

  const tomorrowStr = getLocalDateStr(new Date(Date.now() + 86400000));

  const handleOpenOverview = () => {
    const tomorrow = new Date(Date.now() + 86400000);
    const tDay = tomorrow.getDay();
    const tStr = getLocalDateStr(tomorrow);

    const initialDrafts: DraftOrder[] = companies
      .filter(c => {
        if (!c.recurringOrder) return false;
        const alreadyHasTomorrow = c.orders.some(o => o.date === tStr);
        if (alreadyHasTomorrow) return false;
        const { type, daysOfWeek } = c.recurringOrder.recurrence;
        if (daysOfWeek && daysOfWeek.length > 0) return daysOfWeek.includes(tDay);
        if (type === 'daily') return true;
        if (type === 'weekdays') return tDay >= 1 && tDay <= 5;
        return type === 'weekly' || type === 'custom';
      })
      .map(c => ({
        companyId: c.id,
        companyName: c.name,
        logoUrl: c.logoUrl,
        recurrenceType: c.recurringOrder!.recurrence.type,
        items: c.recurringOrder!.items.map(it => ({ ...it })),
        selected: true,
        isEditing: false
      }));

    if (initialDrafts.length > 0) {
      setDraftOrders(initialDrafts);
      setIsOverviewOpen(true);
    } else {
      alert("Não há novos pedidos recorrentes agendados para amanhã.");
    }
  };

  const handleConfirmLaunch = () => {
    const selectedDrafts = draftOrders.filter(d => d.selected);
    onLaunchBatch(selectedDrafts.map(d => ({
      companyId: d.companyId,
      order: {
        date: tomorrowStr,
        items: d.items.map((it, idx) => ({ ...it, id: `it-auto-${idx}-${Date.now()}` })),
        status: 'pending' as const
      }
    })));
    setIsOverviewOpen(false);
    setDraftOrders([]);
  };

  return (
    <div className="space-y-6 animate-fade-in">
      {isManualModalOpen && <ManualOrderModal companies={companies} products={products} onSave={onAddManualOrder} onClose={() => setIsManualModalOpen(false)} />}

      {/* Action Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white p-6 rounded-xl shadow-sm border border-orange-100">
        <div>
          <h2 className="text-lg font-bold text-amber-800">Operações Rápidas</h2>
          <p className="text-sm text-amber-600">Lançamento em lote ou criação manual pontual.</p>
        </div>
        <div className="flex gap-3 w-full md:w-auto">
          <Button variant="secondary" onClick={handleOpenOverview} className="flex-1 md:flex-none">
            <RocketLaunchIcon className="h-5 w-5 mr-2" />
            Lançar Amanhã
          </Button>
          <Button onClick={() => setIsManualModalOpen(true)} className="flex-1 md:flex-none">
            <PlusIcon className="h-5 w-5 mr-2" />
            Novo Pedido Manual
          </Button>
        </div>
      </div>

      {/* List of Pending Orders */}
      <div className="space-y-4">
        <h3 className="text-xs font-bold text-amber-500 uppercase tracking-[0.2em] ml-1">Fila de Produção e Entrega</h3>
        {pendingOrders.length === 0 ? (
          <Card className="text-center p-20 bg-white/50 border border-dashed border-orange-200 shadow-none">
            <CheckCircleIcon className="mx-auto h-12 w-12 text-orange-200" />
            <p className="mt-4 text-sm text-amber-600 font-medium">A fila está limpa. Todos os pedidos foram confirmados.</p>
          </Card>
        ) : (
          pendingOrders.map(({ company, order }) => (
            <Card key={order.id} className="p-0 border border-orange-50 hover:border-orange-100 group">
              <div className="p-5 flex flex-col md:flex-row justify-between gap-6">
                <div className="flex-1">
                  <div className="flex items-center gap-4 mb-4">
                    <img src={company.logoUrl} className="h-10 w-10 rounded-full border border-orange-50" />
                    <div className="flex-1">
                      <div className="flex items-center gap-2">
                        <h3 className="font-bold text-amber-900">{company.name}</h3>
                        <span className={`text-[9px] font-bold px-2 py-0.5 rounded-full uppercase tracking-tighter ${
                          order.id.includes('manual') 
                            ? 'bg-purple-50 text-purple-600' 
                            : 'bg-blue-50 text-blue-600'
                        }`}>
                          {order.id.includes('manual') ? 'Manual' : 'Agendado'}
                        </span>
                      </div>
                      <p className="text-xs text-amber-500 flex items-center gap-1 mt-0.5">
                        <CalendarDaysIcon className="h-3 w-3" />
                        {new Date(order.date + 'T12:00:00Z').toLocaleDateString('pt-BR', { day: '2-digit', month: 'short', year: 'numeric' })}
                      </p>
                    </div>
                  </div>
                  <div className="bg-orange-50/20 rounded-lg p-3 border border-orange-50 flex flex-wrap gap-2">
                    {order.items.map(it => (
                      <span key={it.id} className="bg-white px-3 py-1.5 rounded-md border border-orange-50 text-xs font-medium text-amber-800 flex items-center gap-2">
                        {it.productName} <span className="text-orange-500 font-bold">{it.quantity}</span>
                      </span>
                    ))}
                  </div>
                </div>
                <div className="flex md:flex-col justify-end gap-2 border-t md:border-t-0 md:border-l border-orange-50 pt-4 md:pt-0 md:pl-6">
                  <Button onClick={() => onConfirmOrder(company.id, order.id)} className="h-11 px-8 text-sm shadow-sm">
                    Confirmar Pedido
                  </Button>
                  <button onClick={() => onDeleteOrder(order.id, company.id)} className="text-red-400 hover:text-red-600 text-xs font-bold transition-colors py-2">
                    Remover da Fila
                  </button>
                </div>
              </div>
            </Card>
          ))
        )}
      </div>

      {/* Tomorrow Overview Modal (Lote) */}
      {isOverviewOpen && (
        <div className="fixed inset-0 bg-amber-900/40 z-50 flex items-center justify-center p-4 backdrop-blur-md animate-fade-in">
          <Card className="w-full max-w-2xl max-h-[85vh] flex flex-col shadow-2xl border-none">
            <div className="px-8 py-6 border-b border-orange-50 flex justify-between items-center bg-white rounded-t-xl">
              <div>
                <h3 className="text-xl font-bold text-amber-900">Confirmar Lançamento de Amanhã</h3>
                <p className="text-xs font-medium text-amber-500 mt-1 uppercase tracking-widest">{new Date(tomorrowStr + 'T12:00:00Z').toLocaleDateString('pt-BR', { day: '2-digit', month: 'long' })}</p>
              </div>
              <button onClick={() => setIsOverviewOpen(false)} className="p-2 hover:bg-orange-50 rounded-full text-amber-400">
                <XMarkIcon className="h-6 w-6" />
              </button>
            </div>
            <div className="flex-1 overflow-y-auto bg-gray-50/30">
              <div className="divide-y divide-orange-50">
                {draftOrders.map((draft) => (
                  <div key={draft.companyId} className={`px-8 py-4 flex items-center gap-4 transition-all ${draft.selected ? 'bg-orange-50/20' : 'opacity-40 grayscale'}`}>
                    <div onClick={() => setDraftOrders(prev => prev.map(d => d.companyId === draft.companyId ? {...d, selected: !d.selected} : d))} className={`h-5 w-5 rounded-md border-2 flex items-center justify-center cursor-pointer ${draft.selected ? 'bg-orange-500 border-orange-500 text-white' : 'border-amber-200 bg-white'}`}>
                      {draft.selected && <CheckIcon className="h-3 w-3 stroke-[3]" />}
                    </div>
                    <div className="flex-1">
                      <p className="font-bold text-amber-900 text-sm">{draft.companyName}</p>
                      <p className="text-[10px] text-amber-600 truncate">{draft.items.map(it => `${it.quantity}x ${it.productName}`).join(', ')}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
            <div className="p-8 border-t border-orange-50 bg-white rounded-b-xl flex items-center justify-between">
              <span className="text-xs font-bold text-amber-500">{draftOrders.filter(d=>d.selected).length} empresas selecionadas</span>
              <div className="flex gap-3">
                <button onClick={() => setIsOverviewOpen(false)} className="px-6 py-2 text-xs font-bold text-amber-400">Cancelar</button>
                <Button onClick={handleConfirmLaunch} disabled={draftOrders.filter(d=>d.selected).length === 0}>Lançar Selecionados</Button>
              </div>
            </div>
          </Card>
        </div>
      )}
    </div>
  );
};

export default ScheduledConfirmation;

