interface ScheduledConfirmationProps {
  companies: Company[];
  products: Product[];
  onConfirmOrder: (companyId: string, orderId: string) => void;
  onDeleteOrder: (orderId: string, companyId: string) => void;
  onLaunchBatch: (orders: { companyId: string, order: Omit<Order, 'id'> }[]) => void;
  onAddManualOrder: (order: Omit<Order, 'id'>, companyId: string) => void;
}

const ScheduledConfirmation: React.FC<ScheduledConfirmationProps> = ({ companies, products, onConfirmOrder, onDeleteOrder, onLaunchBatch, onAddManualOrder }) => {
  const [isOverviewOpen, setIsOverviewOpen] = useState(false);
  const [isManualModalOpen, setIsManualModalOpen] = useState(false);
  const [draftOrders, setDraftOrders] = useState<DraftOrder[]>([]);

  const pendingOrders = companies.flatMap(c => 
    c.orders
      .filter(o => o.status === 'pending')
      .map(o => ({ company: c, order: o }))
  ).sort((a, b) => a.order.date.localeCompare(b.order.date));

  const getLocalDateStr = (date: Date) => {
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
  };

  const tomorrowStr = getLocalDateStr(new Date(Date.now() + 86400000));

  const handleOpenOverview = () => {
    const tomorrow = new Date(Date.now() + 86400000);
    const tDay = tomorrow.getDay();
    const tStr = getLocalDateStr(tomorrow);

    const initialDrafts: DraftOrder[] = companies
      .filter(c => {
        if (!c.recurringOrder) return false;
        const alreadyHasTomorrow = c.orders.some(o => o.date === tStr);
        if (alreadyHasTomorrow) return false;
        const { type, daysOfWeek } = c.recurringOrder.recurrence;
        if (daysOfWeek && daysOfWeek.length > 0) return daysOfWeek.includes(tDay);
        if (type === 'daily') return true;
        if (type === 'weekdays') return tDay >= 1 && tDay <= 5;
        return type === 'weekly' || type === 'custom';
      })
      .map(c => ({
        companyId: c.id,
        companyName: c.name,
        logoUrl: c.logoUrl,
        recurrenceType: c.recurringOrder!.recurrence.type,
        items: c.recurringOrder!.items.map(it => ({ ...it })),
        selected: true,
        isEditing: false
      }));

    if (initialDrafts.length > 0) {
      setDraftOrders(initialDrafts);
      setIsOverviewOpen(true);
    } else {
      alert("Não há novos pedidos recorrentes agendados para amanhã.");
    }
  };

  const handleConfirmLaunch = () => {
    const selectedDrafts = draftOrders.filter(d => d.selected);
    onLaunchBatch(selectedDrafts.map(d => ({
      companyId: d.companyId,
      order: {
        date: tomorrowStr,
        items: d.items.map((it, idx) => ({ ...it, id: `it-auto-${idx}-${Date.now()}` })),
        status: 'pending' as const
      }
    })));
    setIsOverviewOpen(false);
    setDraftOrders([]);
  };

  return (
    <div className="space-y-6 animate-fade-in">
      {isManualModalOpen && <ManualOrderModal companies={companies} products={products} onSave={onAddManualOrder} onClose={() => setIsManualModalOpen(false)} />}

      {/* Action Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white p-6 rounded-xl shadow-sm border border-orange-100">
        <div>
          <h2 className="text-lg font-bold text-amber-800">Operações Rápidas</h2>
          <p className="text-sm text-amber-600">Lançamento em lote ou criação manual pontual.</p>
        </div>
        <div className="flex gap-3 w-full md:w-auto">
          <Button variant="secondary" onClick={handleOpenOverview} className="flex-1 md:flex-none">
            <RocketLaunchIcon className="h-5 w-5 mr-2" />
            Lançar Amanhã
          </Button>
          <Button onClick={() => setIsManualModalOpen(true)} className="flex-1 md:flex-none">
            <PlusIcon className="h-5 w-5 mr-2" />
            Novo Pedido Manual
          </Button>
        </div>
      </div>

      {/* List of Pending Orders */}
      <div className="space-y-4">
        <h3 className="text-xs font-bold text-amber-500 uppercase tracking-[0.2em] ml-1">Fila de Produção e Entrega</h3>
        {pendingOrders.length === 0 ? (
          <Card className="text-center p-20 bg-white/50 border border-dashed border-orange-200 shadow-none">
            <CheckCircleIcon className="mx-auto h-12 w-12 text-orange-200" />
            <p className="mt-4 text-sm text-amber-600 font-medium">A fila está limpa. Todos os pedidos foram confirmados.</p>
          </Card>
        ) : (
          pendingOrders.map(({ company, order }) => (
            <Card key={order.id} className="p-0 border border-orange-50 hover:border-orange-100 group">
              <div className="p-5 flex flex-col md:flex-row justify-between gap-6">
                <div className="flex-1">
                  <div className="flex items-center gap-4 mb-4">
                    <img src={company.logoUrl} className="h-10 w-10 rounded-full border border-orange-50" />
                    <div className="flex-1">
                      <div className="flex items-center gap-2">
                        <h3 className="font-bold text-amber-900">{company.name}</h3>
                        <span className={`text-[9px] font-bold px-2 py-0.5 rounded-full uppercase tracking-tighter ${
                          order.id.includes('manual') 
                            ? 'bg-purple-50 text-purple-600' 
                            : 'bg-blue-50 text-blue-600'
                        }`}>
                          {order.id.includes('manual') ? 'Manual' : 'Agendado'}
                        </span>
                      </div>
                      <p className="text-xs text-amber-500 flex items-center gap-1 mt-0.5">
                        <CalendarDaysIcon className="h-3 w-3" />
                        {new Date(order.date + 'T12:00:00Z').toLocaleDateString('pt-BR', { day: '2-digit', month: 'short', year: 'numeric' })}
                      </p>
                    </div>
                  </div>
                  <div className="bg-orange-50/20 rounded-lg p-3 border border-orange-50 flex flex-wrap gap-2">
                    {order.items.map(it => (
                      <span key={it.id} className="bg-white px-3 py-1.5 rounded-md border border-orange-50 text-xs font-medium text-amber-800 flex items-center gap-2">
                        {it.productName} <span className="text-orange-500 font-bold">{it.quantity}</span>
                      </span>
                    ))}
                  </div>
                </div>
                <div className="flex md:flex-col justify-end gap-2 border-t md:border-t-0 md:border-l border-orange-50 pt-4 md:pt-0 md:pl-6">
                  <Button onClick={() => onConfirmOrder(company.id, order.id)} className="h-11 px-8 text-sm shadow-sm">
                    Confirmar Pedido
                  </Button>
                  <button onClick={() => onDeleteOrder(order.id, company.id)} className="text-red-400 hover:text-red-600 text-xs font-bold transition-colors py-2">
                    Remover da Fila
                  </button>
                </div>
              </div>
            </Card>
          ))
        )}
      </div>

      {/* Tomorrow Overview Modal (Lote) - MODAL MAIOR */}
      {isOverviewOpen && (
        <div className="fixed inset-0 bg-amber-900/40 z-50 flex items-center justify-center p-4 backdrop-blur-md animate-fade-in">
          <Card className="w-full max-w-4xl max-h-[90vh] flex flex-col shadow-2xl border-none">
            <div className="px-10 py-8 border-b border-orange-50 flex justify-between items-center bg-white rounded-t-xl">
              <div>
                <h3 className="text-2xl font-black text-amber-900">Confirmar Lançamento de Amanhã</h3>
                <p className="text-sm font-bold text-amber-500 mt-1 uppercase tracking-[0.2em]">{new Date(tomorrowStr + 'T12:00:00Z').toLocaleDateString('pt-BR', { day: '2-digit', month: 'long' })}</p>
              </div>
              <button onClick={() => setIsOverviewOpen(false)} className="p-3 hover:bg-orange-50 rounded-full text-amber-400 transition-colors">
                <XMarkIcon className="h-8 w-8" />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto bg-gray-50/30 p-4">
              <div className="grid grid-cols-1 gap-3">
                {draftOrders.map((draft) => (
                  <div 
                    key={draft.companyId} 
                    onClick={() => setDraftOrders(prev => prev.map(d => d.companyId === draft.companyId ? {...d, selected: !d.selected} : d))}
                    className={`px-8 py-5 flex items-center gap-6 rounded-xl border-2 transition-all cursor-pointer shadow-sm ${
                        draft.selected 
                        ? 'bg-white border-orange-500 shadow-orange-100' 
                        : 'bg-white/50 border-transparent opacity-50 grayscale'
                    }`}
                  >
                    <div className={`h-7 w-7 rounded-lg border-2 flex items-center justify-center transition-all ${draft.selected ? 'bg-orange-500 border-orange-500 text-white' : 'border-amber-200 bg-white'}`}>
                      {draft.selected && <CheckIcon className="h-5 w-5 stroke-[4]" />}
                    </div>
                    <img src={draft.logoUrl} className="h-12 w-12 rounded-full border border-orange-50 shadow-sm" />
                    <div className="flex-1">
                      <p className="font-black text-amber-900 text-lg">{draft.companyName}</p>
                      <div className="flex flex-wrap gap-x-4 gap-y-1 mt-1">
                        {draft.items.map((it, idx) => (
                           <span key={idx} className="text-xs font-bold text-amber-600">
                              {it.quantity}x <span className="text-amber-800">{it.productName}</span>
                           </span>
                        ))}
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="p-10 border-t border-orange-50 bg-white rounded-b-xl flex flex-col sm:flex-row items-center justify-between gap-6">
              <div className="flex items-center gap-3">
                 <div className="bg-orange-100 text-orange-600 h-10 w-10 rounded-full flex items-center justify-center font-black">
                    {draftOrders.filter(d=>d.selected).length}
                 </div>
                 <span className="text-sm font-black text-amber-800 uppercase tracking-widest">Empresas selecionadas para lançamento</span>
              </div>
              <div className="flex gap-4 w-full sm:w-auto">
                <button onClick={() => setIsOverviewOpen(false)} className="px-8 py-3 text-sm font-black text-amber-400 hover:text-amber-600 transition-colors">Cancelar</button>
                <Button onClick={handleConfirmLaunch} disabled={draftOrders.filter(d=>d.selected).length === 0} className="px-10 py-4 text-base shadow-xl flex-1 sm:flex-none">
                    Lançar Pedidos Agora
                </Button>
              </div>
            </div>
          </Card>
        </div>
      )}
    </div>
  );
};

