import React, { useState } from 'react';
import { Company, Order, OrderItem, Product } from '../types';
import Card from './common/Card';
import Button from './common/Button';
import Input from './common/Input';
import { CheckCircleIcon, TrashIcon, CalendarDaysIcon, XMarkIcon, CheckIcon, PlusIcon } from './Icons';

// Helper para pegar string YYYY-MM-DD
const getLocalDateStr = (date: Date) => {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

// Modal para criação de pedido manual pontual
const ManualOrderModal = ({ companies, products, onSave, onClose }: { 
  companies: Company[], 
  products: Product[], 
  onSave: (order: Omit<Order, 'id'>, companyId: string) => void, 
  onClose: () => void 
}) => {
  const [selectedCompanyId, setSelectedCompanyId] = useState('');
  const [orderDate, setOrderDate] = useState(getLocalDateStr(new Date()));
  const [items, setItems] = useState<Omit<OrderItem, 'id'>[]>([{ productName: '', quantity: 1 }]);

  const handleItemChange = (index: number, field: 'productName' | 'quantity', value: string | number) => {
    const newItems = [...items];
    if (field === 'quantity') {
      newItems[index][field] = Number(value) < 1 ? 1 : Number(value);
    } else {
      newItems[index][field] = value as string;
    }
    setItems(newItems);
  };

  const addItem = () => setItems([...items, { productName: '', quantity: 1 }]);
  const removeItem = (index: number) => setItems(items.filter((_, i) => i !== index));

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedCompanyId) { alert('Selecione uma empresa.'); return; }
    const validItems = items.filter(it => it.productName !== '');
    if (validItems.length === 0) { alert('Adicione pelo menos um produto.'); return; }

    onSave({
      date: orderDate,
      items: validItems.map((it, idx) => ({ ...it, id: `it-manual-${idx}-${Date.now()}` })),
      status: 'pending'
    }, selectedCompanyId);
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-amber-900/40 z-50 flex items-center justify-center p-4 backdrop-blur-sm animate-fade-in">
      <Card className="w-full max-w-lg shadow-2xl border-none">
        <div className="p-6 border-b border-orange-50 flex justify-between items-center bg-white rounded-t-xl">
          <h3 className="text-xl font-black text-amber-900">Novo Pedido Manual</h3>
          <button onClick={onClose} className="text-amber-400 hover:text-amber-600 transition-colors">
            <XMarkIcon className="h-6 w-6" />
          </button>
        </div>
        <form onSubmit={handleSubmit} className="p-8 space-y-5 bg-white rounded-b-xl">
          <div>
            <label className="block text-xs font-black text-amber-500 uppercase tracking-widest mb-2">Empresa Cliente</label>
            <select 
              value={selectedCompanyId} 
              onChange={e => setSelectedCompanyId(e.target.value)}
              required
              className="w-full px-4 py-3 bg-orange-50/30 border-2 border-orange-100 rounded-xl focus:border-orange-500 outline-none text-sm font-bold text-amber-900 transition-all"
            >
              <option value="">Selecione...</option>
              {companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-xs font-black text-amber-500 uppercase tracking-widest mb-2">Data de Entrega</label>
            <Input label="" type="date" value={orderDate} onChange={e => setOrderDate(e.target.value)} required />
          </div>
          <div className="space-y-3 pt-2">
            <label className="block text-xs font-black text-amber-500 uppercase tracking-widest mb-2">Produtos e Quantidades</label>
            {items.map((item, idx) => (
              <div key={idx} className="flex gap-2 items-end animate-fade-in">
                <div className="flex-1">
                  <select 
                    value={item.productName} 
                    onChange={e => handleItemChange(idx, 'productName', e.target.value)}
                    required
                    className="w-full px-3 py-2 bg-white border border-orange-200 rounded-lg text-sm font-medium"
                  >
                    <option value="">Produto...</option>
                    {products.map(p => <option key={p.id} value={p.name}>{p.name}</option>)}
                  </select>
                </div>
                <div className="w-20">
                  <input 
                    type="number" 
                    min="1" 
                    value={item.quantity} 
                    onChange={e => handleItemChange(idx, 'quantity', e.target.value)} 
                    className="w-full px-3 py-2 bg-white border border-orange-200 rounded-lg text-sm text-center font-black text-orange-600"
                  />
                </div>
                <button type="button" onClick={() => removeItem(idx)} className="p-2 text-red-300 hover:text-red-500 transition-colors">
                  <TrashIcon className="h-5 w-5" />
                </button>
              </div>
            ))}
            <button type="button" onClick={addItem} className="text-xs font-black text-orange-600 flex items-center gap-1 hover:underline pt-1">
              <PlusIcon className="h-4 w-4" /> ADICIONAR ITEM
            </button>
          </div>
          <div className="pt-6 flex gap-3">
            <Button type="button" variant="secondary" onClick={onClose} className="flex-1">Cancelar</Button>
            <Button type="submit" className="flex-1 shadow-lg shadow-orange-100">Criar Pedido</Button>
          </div>
        </form>
      </Card>
    </div>
  );
};

interface ScheduledConfirmationProps {
  companies: Company[];
  products: Product[];
  onConfirmOrder: (companyId: string, orderId: string) => void;
  onDeleteOrder: (orderId: string, companyId: string) => void;
  onLaunchBatch: (orders: { companyId: string, order: Omit<Order, 'id'> }[]) => void;
  onAddManualOrder: (order: Omit<Order, 'id'>, companyId: string) => void;
}

const ScheduledConfirmation: React.FC<ScheduledConfirmationProps> = ({ companies, products, onConfirmOrder, onDeleteOrder, onLaunchBatch, onAddManualOrder }) => {
  const [isManualModalOpen, setIsManualModalOpen] = useState(false);

  const todayStr = getLocalDateStr(new Date());
  const tomorrow = new Date(Date.now() + 86400000);
  const tomorrowStr = getLocalDateStr(tomorrow);
  const tomorrowDay = tomorrow.getDay();

  // 1. Pega pedidos pendentes reais (os que já foram lançados mas não confirmados)
  const pendingOrders = companies.flatMap(c => 
    c.orders
      .filter(o => o.status === 'pending')
      .map(o => ({ company: c, order: o, isDraft: false }))
  );

  // 2. Projeta os pedidos de AMANHÃ que ainda não existem no sistema
  const draftOrders = companies
    .filter(c => {
      if (!c.recurringOrder) return false;
      const alreadyHasTomorrow = c.orders.some(o => o.date === tomorrowStr);
      if (alreadyHasTomorrow) return false;

      const { type, daysOfWeek } = c.recurringOrder.recurrence;
      if (daysOfWeek && daysOfWeek.length > 0) return daysOfWeek.includes(tomorrowDay);
      if (type === 'daily') return true;
      if (type === 'weekdays') return tomorrowDay >= 1 && tomorrowDay <= 5;
      return type === 'weekly' || type === 'custom';
    })
    .map(c => ({
      company: c,
      order: {
        id: `draft-tomorrow-${c.id}`,
        date: tomorrowStr,
        items: c.recurringOrder!.items.map((it, idx) => ({ ...it, id: `it-draft-${idx}` })),
        status: 'pending' as const
      },
      isDraft: true
    }));

  // Une e ordena (Hoje no topo, amanhã depois)
  const allQueueItems = [...pendingOrders, ...draftOrders].sort((a, b) => a.order.date.localeCompare(b.order.date));

  const handleConfirmAction = (item: typeof allQueueItems[0]) => {
    if (item.isDraft) {
      // Lança e confirma o pedido projetado em um passo só
      onLaunchBatch([{
        companyId: item.company.id,
        order: {
          date: item.order.date,
          items: item.order.items.map(it => ({ id: `it-real-${Date.now()}-${Math.random()}`, productName: it.productName, quantity: it.quantity })),
          status: 'confirmed'
        }
      }]);
    } else {
      onConfirmOrder(item.company.id, item.order.id);
    }
  };

  return (
    <div className="space-y-8 animate-fade-in">
      {isManualModalOpen && <ManualOrderModal companies={companies} products={products} onSave={onAddManualOrder} onClose={() => setIsManualModalOpen(false)} />}

      {/* Action Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white p-8 rounded-2xl shadow-sm border border-orange-100">
        <div>
          <h2 className="text-2xl font-black text-amber-900">Fila de Produção</h2>
          <p className="text-sm font-bold text-amber-500 mt-1">Gerencie pedidos de hoje e previsões para amanhã em um só lugar.</p>
        </div>
        <Button onClick={() => setIsManualModalOpen(true)} className="w-full md:w-auto px-8 py-4 text-base font-black shadow-xl shadow-orange-100">
          <PlusIcon className="h-6 w-6 mr-2" />
          PEDIDO MANUAL
        </Button>
      </div>

      {/* Grid of Items */}
      <div className="space-y-6">
        <h3 className="text-xs font-black text-amber-400 uppercase tracking-[0.3em] ml-2 flex items-center gap-2">
            <span className="h-1.5 w-1.5 bg-orange-500 rounded-full"></span>
            Pedidos Aguardando Confirmação
        </h3>

        {allQueueItems.length === 0 ? (
          <Card className="text-center p-24 bg-white/40 border-2 border-dashed border-orange-100 shadow-none rounded-3xl">
            <CheckCircleIcon className="mx-auto h-16 w-16 text-orange-200" />
            <h4 className="mt-6 text-xl font-black text-amber-900">Fila Vazia!</h4>
            <p className="mt-2 text-sm font-bold text-amber-500">Não há pedidos manuais pendentes nem agendados para amanhã.</p>
          </Card>
        ) : (
          <div className="grid grid-cols-1 gap-4">
            {allQueueItems.map((item) => (
              <Card 
                key={item.order.id} 
                className={`p-0 border-2 transition-all group overflow-visible ${
                  item.isDraft 
                    ? 'border-blue-100 bg-blue-50/20' 
                    : 'border-orange-50 bg-white hover:border-orange-200'
                }`}
              >
                <div className="p-6 md:p-8 flex flex-col md:flex-row justify-between gap-8">
                  <div className="flex-1">
                    <div className="flex items-start gap-6 mb-6">
                      <div className="relative">
                        <img src={item.company.logoUrl} className="h-16 w-16 rounded-2xl border-2 border-white shadow-md object-cover" />
                        <div className={`absolute -bottom-2 -right-2 h-6 w-6 rounded-full border-2 border-white flex items-center justify-center ${item.isDraft ? 'bg-blue-500' : 'bg-orange-500'}`}>
                           <CalendarDaysIcon className="h-3 w-3 text-white" />
                        </div>
                      </div>
                      <div className="flex-1">
                        <div className="flex flex-wrap items-center gap-3">
                          <h3 className="text-2xl font-black text-amber-900 leading-none">{item.company.name}</h3>

                          {/* Badges de Status */}
                          {item.isDraft ? (
                            <span className="text-[10px] font-black px-3 py-1 rounded-lg uppercase tracking-wider bg-blue-600 text-white shadow-sm">
                               Programado (Amanhã)
                            </span>
                          ) : item.order.id.includes('manual') ? (
                            <span className="text-[10px] font-black px-3 py-1 rounded-lg uppercase tracking-wider bg-purple-500 text-white shadow-sm">
                               Pedido Manual
                            </span>
                          ) : (
                            <span className="text-[10px] font-black px-3 py-1 rounded-lg uppercase tracking-wider bg-orange-500 text-white shadow-sm">
                               Agendado (Hoje)
                            </span>
                          )}
                        </div>

                        <p className="text-sm font-bold text-amber-500 flex items-center gap-2 mt-2">
                          <CalendarDaysIcon className="h-4 w-4" />
                          Data prevista: <span className="text-amber-800">{new Date(item.order.date + 'T12:00:00Z').toLocaleDateString('pt-BR', { day: '2-digit', month: 'long' })}</span>
                          {item.order.date === tomorrowStr && <span className="bg-blue-100 text-blue-600 px-2 rounded text-[10px] font-black uppercase ml-2 animate-pulse">Previsão</span>}
                        </p>
                      </div>
                    </div>

                    {/* Lista de Produtos no Card */}
                    <div className="bg-white/60 rounded-2xl p-4 border border-orange-100/50 flex flex-wrap gap-3 shadow-inner">
                      {item.order.items.map(it => (
                        <div key={it.id} className="bg-white px-4 py-2.5 rounded-xl border border-orange-100/50 shadow-sm flex items-center gap-3">
                          <span className="h-2 w-2 bg-orange-400 rounded-full"></span>
                          <span className="text-sm font-bold text-amber-900">{it.productName}</span>
                          <span className="text-base font-black text-orange-600 ml-1">{it.quantity} un</span>
                        </div>
                      ))}
                    </div>
                  </div>

                  {/* Coluna de Ações */}
                  <div className="flex flex-row md:flex-col justify-end items-center md:items-stretch gap-3 md:min-w-[220px] md:pl-8 md:border-l border-orange-100">
                    <Button 
                      onClick={() => handleConfirmAction(item)} 
                      className={`h-14 px-10 text-base shadow-lg font-black transition-all hover:scale-105 active:scale-95 ${
                        item.isDraft ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-100' : 'shadow-orange-100'
                      }`}
                    >
                      {item.isDraft ? 'Confirmar para Amanhã' : 'Confirmar Entrega'}
                    </Button>

                    {!item.isDraft ? (
                      <button 
                        onClick={() => onDeleteOrder(item.order.id, item.company.id)} 
                        className="text-red-400 hover:text-red-600 text-xs font-black uppercase tracking-widest transition-colors py-2 px-4"
                      >
                        Cancelar
                      </button>
                    ) : (
                       <span className="text-[10px] font-bold text-blue-400 italic text-center px-4 leading-tight opacity-70">
                          Previsão baseada no contrato. Clique para confirmar produção.
                       </span>
                    )}
                  </div>
                </div>
              </Card>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

