    } else {
      onConfirmOrder(item.company.id, item.order.id);
    }
  };

  const handleLaunchAllTomorrow = () => {
    if (draftOrders.length === 0) {
      alert("Não há pedidos projetados para amanhã no momento.");
      return;
    }

    if (confirm(`Deseja lançar todos os ${draftOrders.length} pedidos previstos para amanhã?`)) {
