          disabled={draftOrders.length === 0}
        >
          <RocketLaunchIcon className="h-5 w-5 mr-2" />
          LANÇAR PEDIDOS DE AMANHÃ ({draftOrders.length})
        </Button>
      </div>

      <div className="space-y-3">
        {allQueueItems.length === 0 ? (
