  const tomorrow = new Date(Date.now() + 86400000);
  const tomorrowStr = getLocalDateStr(tomorrow);
  const tomorrowDay = tomorrow.getDay();

  // 1. Pedidos pendentes reais
  const pendingOrders = companies.flatMap(c => 
    c.orders
      .filter(o => o.status === 'pending')
      .map(o => ({ company: c, order: o, isDraft: false }))
  );

  // 2. Projeções para AMANHÃ
  const draftOrders = companies
    .filter(c => {
      if (!c.recurringOrder) return false;
      const alreadyHasTomorrow = c.orders.some(o => o.date === tomorrowStr);
      if (alreadyHasTomorrow) return false;

      const { type, daysOfWeek } = c.recurringOrder.recurrence;
      if (daysOfWeek && daysOfWeek.length > 0) return daysOfWeek.includes(tomorrowDay);
      if (type === 'daily') return true;
      if (type === 'weekdays') return tomorrowDay >= 1 && tomorrowDay <= 5;
      return type === 'weekly' || type === 'custom';
    })
    .map(c => ({
      company: c,
      order: {
        id: `draft-tomorrow-${c.id}`,
        date: tomorrowStr,
        items: c.recurringOrder!.items.map((it, idx) => ({ ...it, id: `it-draft-${idx}` })),
        status: 'pending' as const
      },
      isDraft: true
    }));

  const allQueueItems = [...pendingOrders, ...draftOrders].sort((a, b) => a.order.date.localeCompare(b.order.date));

  const handleConfirmAll = () => {
    if (allQueueItems.length === 0) {
      alert("Não há pedidos na fila para confirmar.");
      return;
    }

    if (confirm(`Deseja confirmar todos os ${allQueueItems.length} pedidos da fila?`)) {
      const draftsToLaunch = draftOrders.map(d => ({
        companyId: d.company.id,
        order: {
          date: d.order.date,
          items: d.order.items.map(it => ({ id: `it-batch-${Date.now()}-${Math.random()}`, productName: it.productName, quantity: it.quantity })),
          status: 'confirmed'
        }
      }));

      // Primeiro lança os drafts como confirmados
      if (draftsToLaunch.length > 0) {
        onLaunchBatch(draftsToLaunch);
      }

      // Depois confirma os que já existem
      pendingOrders.forEach(p => {
        onConfirmOrder(p.company.id, p.order.id);
      });
    }
  };

  const handleSaveEdit = (newItems: Omit<OrderItem, 'id'>[]) => {
    if (!editingItem) return;

    if (editingItem.isDraft) {
      // Se era um draft, ao editar nós o transformamos em um pedido manual real pendente
      onAddManualOrder({
        date: editingItem.order.date,
