const loadFromLocalStorage = <T,>(key: string, defaultValue: T): T => {
    try {
        const storedValue = localStorage.getItem(key);
        if (storedValue) return JSON.parse(storedValue);
    } catch (error) { console.error(`Error loading ${key}`, error); }
    return defaultValue;
};

const saveToLocalStorage = <T,>(key: string, value: T) => {
    try { localStorage.setItem(key, JSON.stringify(value)); } catch (error) { console.error(`Error saving ${key}`, error); }
};

const initialCompanies: Company[] = [
    {
      id: '1',
      name: 'Padaria Doce Pão',
      cnpj: '12.345.678/0001-99',
      address: 'Rua das Flores, 123, São Paulo - SP',
      cep: '01234-567',
      phone: '(11) 98765-4321',
      logoUrl: 'https://picsum.photos/seed/bakerylogo/200',
      doorSale: true,
      orders: [],
      productSettings: [
        { productId: 'prod-1', buys: true, price: 0.75 },
        { productId: 'prod-2', buys: true, price: 5.50 }
      ]
    }
];

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);
  const [currentView, setCurrentView] = useState<View>('companies');
  const [companies, setCompanies] = useState<Company[]>(() => loadFromLocalStorage('companies', initialCompanies));
  const [employees, setEmployees] = useState<Employee[]>(() => loadFromLocalStorage('employees', []));
  const [products, setProducts] = useState<Product[]>(() => loadFromLocalStorage('products', []));
  const [selectedCompanyId, setSelectedCompanyId] = useState<string | null>(null);
  const [viewingCompanyId, setViewingCompanyId] = useState<string | null>(null);

  useEffect(() => { saveToLocalStorage('companies', companies); }, [companies]);
  useEffect(() => { saveToLocalStorage('employees', employees); }, [employees]);
  useEffect(() => { saveToLocalStorage('products', products); }, [products]);

  // Função robusta para confirmar tudo da fila de uma vez
  const handleConfirmAllQueue = (data: { drafts: { companyId: string, order: Omit<Order, 'id'> }[], existing: { companyId: string, orderId: string }[] }) => {
    setCompanies(prev => prev.map(c => {
      let updatedOrders = [...c.orders];

      // 1. Confirmar os que já existem
      const existingIds = data.existing.filter(e => e.companyId === c.id).map(e => e.orderId);
      if (existingIds.length > 0) {
        updatedOrders = updatedOrders.map(o => existingIds.includes(o.id) ? { ...o, status: 'confirmed' } : o);
      }

      // 2. Lançar os novos (drafts)
      const draftsForThisCompany = data.drafts.filter(d => d.companyId === c.id);
      if (draftsForThisCompany.length > 0) {
        const newOrders: Order[] = draftsForThisCompany.map(d => ({
          ...d.order,
          id: `batch-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
          status: 'confirmed'
        }));
        updatedOrders = [...newOrders, ...updatedOrders];
      }

      return { ...c, orders: updatedOrders };
    }));
  };

  const handleConfirmOrder = (companyId: string, orderId: string) => {
    setCompanies(prev => prev.map(c => {
      if (c.id === companyId) {
        return {
          ...c,
          orders: c.orders.map(o => o.id === orderId ? { ...o, status: 'confirmed' } : o)
        };
      }
      return c;
    }));
  };

  const handleLaunchBatch = (ordersToLaunch: { companyId: string, order: Omit<Order, 'id'> }[]) => {
    setCompanies(prev => prev.map(c => {
      const companyOrdersToLaunch = ordersToLaunch.filter(ol => ol.companyId === c.id);
      if (companyOrdersToLaunch.length > 0) {
        const newOrders: Order[] = companyOrdersToLaunch.map(ol => ({
          ...ol.order,
          id: `manual-batch-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`
        }));
        return {
          ...c,
          orders: [...newOrders, ...c.orders]
        };
      }
      return c;
    }));
  };

  const handleUpdateRecurringOrder = (companyId: string, config: RecurringOrderConfig) => {
    setCompanies(prev => prev.map(c => c.id === companyId ? { ...c, recurringOrder: config } : c));
  };

  const handleLogin = (user: string, pass: string): boolean => {
    if (user === 'admin' && pass === 'admin') {
      setIsAuthenticated(true);
      return true;
    }
    return false;
  };

  const handleLogout = () => { setIsAuthenticated(false); setViewingCompanyId(null); };

  const handleSetCurrentView = (view: View) => {
    setCurrentView(view);
    setViewingCompanyId(null);
    const filtered = view === 'door-sales' ? companies.filter(c => c.doorSale) : companies; 
    setSelectedCompanyId(filtered.length > 0 ? filtered[0].id : null);
  }

  const handleAddCompany = (newCompanyData: Omit<Company, 'id' | 'orders'>) => {
    const newCompany: Company = { ...newCompanyData, id: Date.now().toString(), orders: [], productSettings: [] };
    setCompanies(prev => [...prev, newCompany]);
  };

  const handleUpdateCompany = (updatedCompany: Company) => {
    setCompanies(prev => prev.map(c => c.id === updatedCompany.id ? updatedCompany : c));
  };

  const handleDeleteCompany = (companyId: string) => {
    const remaining = companies.filter(c => c.id !== companyId);
    setCompanies(remaining);
    if (selectedCompanyId === companyId) setSelectedCompanyId(remaining.length > 0 ? remaining[0].id : null);
  };

  const handleAddOrder = (newOrderData: Omit<Order, 'id'>, companyId?: string) => {
    const targetId = companyId || selectedCompanyId;
    if (!targetId) return;
    setCompanies(prev => prev.map(c => {
      if (c.id === targetId) {
        const newOrder: Order = { ...newOrderData, id: `order-manual-${Date.now()}`, status: 'pending' as const };
        return { ...c, orders: [newOrder, ...c.orders].sort((a, b) => b.date.localeCompare(a.date)) };
      }
      return c;
    }));
  };

  const handleDeleteOrder = (orderId: string, companyId?: string) => {
    const targetId = companyId || selectedCompanyId;
    if (!targetId) return;
    setCompanies(prev => prev.map(c => c.id === targetId ? { ...c, orders: c.orders.filter(o => o.id !== orderId) } : c));
  };

  const handleUpdateOrderSignature = (orderId: string, signature: string) => {
    if (!selectedCompanyId) return;
    setCompanies(prev => prev.map(c => c.id === selectedCompanyId ? { ...c, orders: c.orders.map(o => o.id === orderId ? { ...o, signature } : o) } : c));
  };

  const renderContent = () => {
    const selectedCompany = companies.find(c => c.id === selectedCompanyId) || null;
    const companyToView = companies.find(c => c.id === viewingCompanyId);

    if (currentView === 'companies' && companyToView) {
      return <CompanyDetailView company={companyToView} products={products} onUpdate={handleUpdateCompany} onUpdateProductSettings={(id, s) => setCompanies(prev => prev.map(c => c.id === id ? { ...c, productSettings: s } : c))} onBack={() => setViewingCompanyId(null)} />
    }

    switch (currentView) {
      case 'companies': return <CompanyManagement companies={companies} onAdd={handleAddCompany} onUpdate={handleUpdateCompany} onDelete={handleDeleteCompany} onViewCompany={setViewingCompanyId} />;
      case 'employees': return <EmployeeManagement employees={employees} onAddEmployee={(e) => setEmployees(prev => [...prev, { ...e, id: `emp-${Date.now()}`, status: 'Ativo' }])} onDeleteEmployee={(id) => setEmployees(prev => prev.filter(e => e.id !== id))} onUpdateEmployeeStatus={(id, s) => setEmployees(prev => prev.map(e => e.id === id ? { ...e, status: s } : e))} />;
      case 'scheduled-confirmation': return <ScheduledConfirmation companies={companies} products={products} onConfirmAllQueue={handleConfirmAllQueue} onDeleteOrder={handleDeleteOrder} onAddManualOrder={handleAddOrder} />;
      case 'orders': return <OrderManagement companies={companies} selectedCompany={selectedCompany} products={products} onSelectCompany={setSelectedCompanyId} onAddOrder={handleAddOrder} onDeleteOrder={(id) => handleDeleteOrder(id)} onUpdateOrderSignature={handleUpdateOrderSignature} onUpdateRecurringOrder={handleUpdateRecurringOrder} isDoorSaleMode={false} />;
      case 'door-sales': return <OrderManagement companies={companies.filter(c => c.doorSale)} selectedCompany={selectedCompany} products={products} onSelectCompany={setSelectedCompanyId} onAddOrder={handleAddOrder} onDeleteOrder={(id) => handleDeleteOrder(id)} onUpdateOrderSignature={handleUpdateOrderSignature} isDoorSaleMode={true} />;
      case 'products': return <ProductManagement products={products} onAdd={(p) => setProducts(prev => [...prev, { ...p, id: `prod-${Date.now()}` }])} onUpdate={(p) => setProducts(prev => prev.map(prod => prod.id === p.id ? p : prod))} onDelete={(id) => setProducts(prev => prev.filter(p => p.id !== id))} />;
      default: return null;
    }
  };

  if (!isAuthenticated) return <LoginPage onLogin={handleLogin} />;

  const headerInfo = {
    companies: { icon: <BuildingStorefrontIcon className="h-8 w-8 text-orange-500" />, title: 'Gerenciamento de Empresas', subtitle: 'Adicione, visualize e edite as informações das suas empresas clientes.' },
    employees: { icon: <UsersIcon className="h-8 w-8 text-orange-500" />, title: 'Gerenciamento de Funcionários', subtitle: 'Gerencie a equipe da Engenho do Pão.' },
    'scheduled-confirmation': { icon: <CheckCircleIcon className="h-8 w-8 text-orange-500" />, title: 'Fila de Produção & Confirmação', subtitle: 'Gerencie todos os pedidos aguardando confirmação (agendados e manuais).' },
    orders: { icon: <ClipboardDocumentListIcon className="h-8 w-8 text-orange-500" />, title: 'Histórico de pedidos', subtitle: 'Acompanhe o registro histórico de pedidos de todos os clientes.' },
    'door-sales': { icon: <ShoppingBagIcon className="h-8 w-8 text-orange-500" />, title: 'Venda na Porta', subtitle: 'Gerencie pedidos específicos de venda na porta.' },
    products: { icon: <TagIcon className="h-8 w-8 text-orange-500" />, title: 'Gerenciamento de Produtos', subtitle: 'Cadastre e organize os produtos oferecidos pela padaria.' },
  };

  return (
    <div className="flex h-screen bg-orange-50 font-sans">
      <Sidebar currentView={currentView} setCurrentView={handleSetCurrentView} onLogout={handleLogout} />
      <main className="flex-1 p-4 md:p-8 overflow-y-auto">
        {!(currentView === 'companies' && viewingCompanyId) && (
          <header className="mb-8">
              <div className="flex items-center gap-4">
                  {headerInfo[currentView].icon}
                  <h1 className="text-3xl font-bold text-amber-800">{headerInfo[currentView].title}</h1>
              </div>
              <p className="text-amber-600 mt-1">{headerInfo[currentView].subtitle}</p>
          </header>
        )}
        {renderContent()}
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Company, Order, OrderItem, Product } from '../types';
import Card from './common/Card';
import Button from './common/Button';
import { CheckCircleIcon, CalendarDaysIcon, RocketLaunchIcon, TrashIcon, PencilSquareIcon, XMarkIcon, PlusIcon } from './Icons';

const getLocalDateStr = (date: Date) => {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

const EditOrderModal = ({ order, products, onSave, onClose }: any) => {
  const [items, setItems] = useState<Omit<OrderItem, 'id'>[]>(
    order.order.items.map((it: any) => ({ productName: it.productName, quantity: it.quantity }))
  );

  const handleItemChange = (index: number, field: 'productName' | 'quantity', value: any) => {
    const newItems = [...items];
    newItems[index][field] = field === 'quantity' ? Math.max(1, Number(value)) : value;
    setItems(newItems);
  };

  const addItem = () => setItems([...items, { productName: '', quantity: 1 }]);
  const removeItem = (index: number) => setItems(items.filter((_, i) => i !== index));

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const validItems = items.filter(it => it.productName !== '');
    if (validItems.length === 0) return;
    onSave(validItems);
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-amber-900/40 z-50 flex items-center justify-center p-4 backdrop-blur-sm animate-fade-in">
      <Card className="w-full max-w-lg shadow-2xl border-none">
        <div className="p-6 border-b border-orange-50 flex justify-between items-center bg-white rounded-t-xl">
          <div className="flex items-center gap-3">
            <img src={order.company.logoUrl} className="h-10 w-10 rounded-lg object-cover" />
            <h3 className="text-lg font-black text-amber-900">Editar Pedido - {order.company.name}</h3>
          </div>
          <button onClick={onClose} className="text-amber-400 hover:text-amber-600"><XMarkIcon className="h-6 w-6" /></button>
        </div>
        <form onSubmit={handleSubmit} className="p-8 space-y-5 bg-white rounded-b-xl max-h-[70vh] overflow-y-auto">
          <div className="space-y-3">
            {items.map((item, idx) => (
              <div key={idx} className="flex gap-2 items-end">
                <div className="flex-1">
                  <select 
                    value={item.productName} 
                    onChange={e => handleItemChange(idx, 'productName', e.target.value)}
                    className="w-full px-3 py-2 bg-orange-50/30 border border-orange-100 rounded-lg text-sm"
                  >
                    <option value="">Produto...</option>
                    {products.map((p: any) => <option key={p.id} value={p.name}>{p.name}</option>)}
                  </select>
                </div>
                <div className="w-20">
                  <input type="number" value={item.quantity} onChange={e => handleItemChange(idx, 'quantity', e.target.value)} className="w-full px-3 py-2 border rounded-lg text-center font-black" />
                </div>
                <button type="button" onClick={() => removeItem(idx)} className="text-red-300 p-2"><TrashIcon className="h-5 w-5" /></button>
              </div>
            ))}
            <button type="button" onClick={addItem} className="text-xs font-black text-orange-600 flex items-center gap-1"><PlusIcon className="h-4 w-4" /> ADICIONAR ITEM</button>
          </div>
          <div className="pt-6 flex gap-3">
            <Button type="button" variant="secondary" onClick={onClose} className="flex-1">Cancelar</Button>
            <Button type="submit" className="flex-1">Salvar Alterações</Button>
          </div>
        </form>
      </Card>
    </div>
  );
};

interface ScheduledConfirmationProps {
  companies: Company[];
  products: Product[];
  onConfirmAllQueue: (data: { drafts: any[], existing: any[] }) => void;
  onDeleteOrder: (orderId: string, companyId: string) => void;
  onAddManualOrder: (order: Omit<Order, 'id'>, companyId: string) => void;
}

const ScheduledConfirmation: React.FC<ScheduledConfirmationProps> = ({ companies, products, onConfirmAllQueue, onDeleteOrder, onAddManualOrder }) => {
  const [editingItem, setEditingItem] = useState<any>(null);

  const tomorrowStr = getLocalDateStr(new Date(Date.now() + 86400000));
  const tomorrowDay = new Date(Date.now() + 86400000).getDay();

  const pendingOrders = companies.flatMap(c => 
    c.orders.filter(o => o.status === 'pending').map(o => ({ company: c, order: o, isDraft: false }))
  );

  const draftOrders = companies
    .filter(c => {
      if (!c.recurringOrder || c.orders.some(o => o.date === tomorrowStr)) return false;
      const { type, daysOfWeek } = c.recurringOrder.recurrence;
      return daysOfWeek?.includes(tomorrowDay) || type === 'daily' || (type === 'weekdays' && tomorrowDay >= 1 && tomorrowDay <= 5);
    })
    .map(c => ({
      company: c,
      order: {
        id: `draft-${c.id}`,
        date: tomorrowStr,
        items: c.recurringOrder!.items,
        status: 'pending' as const
      },
      isDraft: true
    }));

  const allQueueItems = [...pendingOrders, ...draftOrders].sort((a, b) => a.order.date.localeCompare(b.order.date));

  const handleConfirmAll = () => {
    if (allQueueItems.length === 0) return;
    if (confirm(`Confirmar todos os ${allQueueItems.length} pedidos da fila?`)) {
      onConfirmAllQueue({
        drafts: draftOrders.map(d => ({ companyId: d.company.id, order: { ...d.order, items: d.order.items.map(it => ({ ...it, id: Math.random().toString() })) } })),
        existing: pendingOrders.map(p => ({ companyId: p.company.id, orderId: p.order.id }))
      });
    }
  };

  const handleSaveEdit = (newItems: any) => {
    if (!editingItem) return;
    if (!editingItem.isDraft) onDeleteOrder(editingItem.order.id, editingItem.company.id);
    onAddManualOrder({ date: editingItem.order.date, items: newItems.map((it: any) => ({ ...it, id: Math.random().toString() })), status: 'pending' }, editingItem.company.id);
  };

  return (
    <div className="space-y-4 animate-fade-in max-w-5xl mx-auto">
      {editingItem && <EditOrderModal order={editingItem} products={products} onSave={handleSaveEdit} onClose={() => setEditingItem(null)} />}

      <div className="flex justify-between items-center bg-white p-5 rounded-xl shadow-sm border border-orange-100">
        <div>
          <h2 className="text-lg font-black text-amber-900 leading-tight">Fila de Produção</h2>
          <p className="text-[10px] font-bold text-amber-500 uppercase">PEDIDOS ATIVOS E PREVISÕES</p>
        </div>
        <Button onClick={handleConfirmAll} className="px-8" disabled={allQueueItems.length === 0}>
          <RocketLaunchIcon className="h-5 w-5 mr-2" />
          Confirmar pedidos de amanhã ({allQueueItems.length})
        </Button>
      </div>

      <div className="space-y-2.5">
        {allQueueItems.length === 0 ? (
          <Card className="text-center p-12 bg-white/40 border-2 border-dashed border-orange-100 shadow-none"><p className="text-sm font-bold text-amber-600">Nenhum pedido na fila.</p></Card>
        ) : (
          allQueueItems.map((item) => (
            <Card key={item.order.id} className="p-4 md:p-5 border border-orange-50 bg-white">
              <div className="flex flex-col md:flex-row justify-between items-center gap-4">

                {/* Esquerda: Empresa */}
                <div className="flex items-center gap-4 flex-1 w-full">
                  <div className="relative">
                    <img src={item.company.logoUrl} className="h-12 w-12 rounded-xl object-cover border border-orange-50 shadow-sm" />
                    <div className="absolute -bottom-1 -right-1 h-5 w-5 rounded-full border-2 border-white flex items-center justify-center bg-orange-500">
                      <CalendarDaysIcon className="h-2.5 w-2.5 text-white" />
                    </div>
                  </div>
                  <div className="min-w-0">
                    <h3 className="text-base font-black text-amber-900 truncate">{item.company.name}</h3>
                    <div className="flex items-center gap-2 mt-0.5">
                      <span className={`text-[9px] font-black px-1.5 py-0.5 rounded ${item.isDraft ? 'bg-amber-100 text-amber-700' : 'bg-orange-100 text-orange-700'} uppercase`}>
                        {item.isDraft ? 'PREVISÃO' : 'PENDENTE'}
                      </span>
                      <span className="text-[10px] font-bold text-orange-400 uppercase">
                        {new Date(item.order.date + 'T12:00:00Z').toLocaleDateString('pt-BR', { day: '2-digit', month: 'long' })}
                      </span>
                    </div>
                  </div>
                </div>

                {/* Centro: Produtos Chips */}
                <div className="flex flex-wrap gap-2 flex-[2] justify-start md:justify-center w-full">
                  {item.order.items.map((it: any, idx: number) => (
                    <div key={idx} className="bg-orange-50/50 px-3 py-1.5 rounded-lg border border-orange-100/50 flex items-center gap-3">
                      <span className="text-xs font-bold text-amber-800">{it.productName}</span>
                      <span className="text-xs font-black text-orange-600">{it.quantity}</span>
                    </div>
                  ))}
                </div>

                {/* Direita: Ações (Apenas Ícones) */}
                <div className="flex items-center gap-1 w-full md:w-auto justify-end">
                  <button onClick={() => setEditingItem(item)} className="p-2.5 text-amber-400 hover:text-amber-600 transition-colors" title="Editar"><PencilSquareIcon className="h-6 w-6" /></button>
                  <button onClick={() => onDeleteOrder(item.order.id, item.company.id)} className="p-2.5 text-red-200 hover:text-red-400 transition-colors" title="Remover"><TrashIcon className="h-6 w-6" /></button>
                </div>

              </div>
            </Card>
          ))
        )}
      </div>
      <p className="text-center text-[10px] font-black text-amber-200 uppercase tracking-widest pt-4">Fim da lista de produção</p>
    </div>
  );
};

export default ScheduledConfirmation;

import React, { useState } from 'react';
import { Company, Order, OrderItem, Product } from '../types';
import Card from './common/Card';
import Button from './common/Button';
import { CheckCircleIcon, CalendarDaysIcon, RocketLaunchIcon, TrashIcon, PencilSquareIcon, XMarkIcon, PlusIcon } from './Icons';

const getLocalDateStr = (date: Date) => {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

const EditOrderModal = ({ order, products, onSave, onClose }: any) => {
  const [items, setItems] = useState<Omit<OrderItem, 'id'>[]>(
    order.order.items.map((it: any) => ({ productName: it.productName, quantity: it.quantity }))
  );

  // FIX: Fixed TypeScript error "Type 'any' is not assignable to type 'never'" by narrowing the field type before assignment.
  // Using direct property access after narrowing avoids the problematic computed property assignment with incompatible types.
  const handleItemChange = (index: number, field: 'productName' | 'quantity', value: any) => {
    const newItems = [...items];
    if (field === 'quantity') {
      newItems[index].quantity = Math.max(1, Number(value));
    } else {
      newItems[index].productName = value;
    }
    setItems(newItems);
  };

  const addItem = () => setItems([...items, { productName: '', quantity: 1 }]);
  const removeItem = (index: number) => setItems(items.filter((_, i) => i !== index));

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const validItems = items.filter(it => it.productName !== '');
    if (validItems.length === 0) return;
    onSave(validItems);
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-amber-900/40 z-50 flex items-center justify-center p-4 backdrop-blur-sm animate-fade-in">
      <Card className="w-full max-w-lg shadow-2xl border-none">
        <div className="p-6 border-b border-orange-50 flex justify-between items-center bg-white rounded-t-xl">
          <div className="flex items-center gap-3">
            <img src={order.company.logoUrl} className="h-10 w-10 rounded-lg object-cover" />
            <h3 className="text-lg font-black text-amber-900">Editar Pedido - {order.company.name}</h3>
          </div>
          <button onClick={onClose} className="text-amber-400 hover:text-amber-600"><XMarkIcon className="h-6 w-6" /></button>
        </div>
        <form onSubmit={handleSubmit} className="p-8 space-y-5 bg-white rounded-b-xl max-h-[70vh] overflow-y-auto">
          <div className="space-y-3">
            {items.map((item, idx) => (
              <div key={idx} className="flex gap-2 items-end">
                <div className="flex-1">
                  <select 
                    value={item.productName} 
                    onChange={e => handleItemChange(idx, 'productName', e.target.value)}
                    className="w-full px-3 py-2 bg-orange-50/30 border border-orange-100 rounded-lg text-sm"
                  >
                    <option value="">Produto...</option>
                    {products.map((p: any) => <option key={p.id} value={p.name}>{p.name}</option>)}
                  </select>
                </div>
                <div className="w-20">
                  <input type="number" value={item.quantity} onChange={e => handleItemChange(idx, 'quantity', e.target.value)} className="w-full px-3 py-2 border rounded-lg text-center font-black" />
                </div>
                <button type="button" onClick={() => removeItem(idx)} className="text-red-300 p-2"><TrashIcon className="h-5 w-5" /></button>
              </div>
            ))}
            <button type="button" onClick={addItem} className="text-xs font-black text-orange-600 flex items-center gap-1"><PlusIcon className="h-4 w-4" /> ADICIONAR ITEM</button>
          </div>
          <div className="pt-6 flex gap-3">
            <Button type="button" variant="secondary" onClick={onClose} className="flex-1">Cancelar</Button>
            <Button type="submit" className="flex-1">Salvar Alterações</Button>
          </div>
        </form>
      </Card>
    </div>
  );
};

interface ScheduledConfirmationProps {
  companies: Company[];
  products: Product[];
  onConfirmAllQueue: (data: { drafts: any[], existing: any[] }) => void;
  onDeleteOrder: (orderId: string, companyId: string) => void;
  onAddManualOrder: (order: Omit<Order, 'id'>, companyId: string) => void;
}

const ScheduledConfirmation: React.FC<ScheduledConfirmationProps> = ({ companies, products, onConfirmAllQueue, onDeleteOrder, onAddManualOrder }) => {
  const [editingItem, setEditingItem] = useState<any>(null);

  const tomorrowStr = getLocalDateStr(new Date(Date.now() + 86400000));
  const tomorrowDay = new Date(Date.now() + 86400000).getDay();

  const pendingOrders = companies.flatMap(c => 
    c.orders.filter(o => o.status === 'pending').map(o => ({ company: c, order: o, isDraft: false }))
  );

  const draftOrders = companies
    .filter(c => {
      if (!c.recurringOrder || c.orders.some(o => o.date === tomorrowStr)) return false;
      const { type, daysOfWeek } = c.recurringOrder.recurrence;
      return daysOfWeek?.includes(tomorrowDay) || type === 'daily' || (type === 'weekdays' && tomorrowDay >= 1 && tomorrowDay <= 5);
    })
    .map(c => ({
      company: c,
      order: {
        id: `draft-${c.id}`,
        date: tomorrowStr,
        items: c.recurringOrder!.items,
        status: 'pending' as const
      },
      isDraft: true
    }));

  const allQueueItems = [...pendingOrders, ...draftOrders].sort((a, b) => a.order.date.localeCompare(b.order.date));

  const handleConfirmAll = () => {
    if (allQueueItems.length === 0) return;
    if (confirm(`Confirmar todos os ${allQueueItems.length} pedidos da fila?`)) {
      onConfirmAllQueue({
        drafts: draftOrders.map(d => ({ companyId: d.company.id, order: { ...d.order, items: d.order.items.map(it => ({ ...it, id: Math.random().toString() })) } })),
        existing: pendingOrders.map(p => ({ companyId: p.company.id, orderId: p.order.id }))
      });
    }
  };

  const handleSaveEdit = (newItems: any) => {
    if (!editingItem) return;
    if (!editingItem.isDraft) onDeleteOrder(editingItem.order.id, editingItem.company.id);
    onAddManualOrder({ date: editingItem.order.date, items: newItems.map((it: any) => ({ ...it, id: Math.random().toString() })), status: 'pending' }, editingItem.company.id);
  };

  return (
    <div className="space-y-4 animate-fade-in max-w-5xl mx-auto">
      {editingItem && <EditOrderModal order={editingItem} products={products} onSave={handleSaveEdit} onClose={() => setEditingItem(null)} />}

      <div className="flex justify-between items-center bg-white p-5 rounded-xl shadow-sm border border-orange-100">
        <div>
          <h2 className="text-lg font-black text-amber-900 leading-tight">Fila de Produção</h2>
          <p className="text-[10px] font-bold text-amber-500 uppercase">PEDIDOS ATIVOS E PREVISÕES</p>
        </div>
        <Button onClick={handleConfirmAll} className="px-8" disabled={allQueueItems.length === 0}>
          <RocketLaunchIcon className="h-5 w-5 mr-2" />
          Confirmar pedidos de amanhã ({allQueueItems.length})
        </Button>
      </div>

      <div className="space-y-2.5">
        {allQueueItems.length === 0 ? (
          <Card className="text-center p-12 bg-white/40 border-2 border-dashed border-orange-100 shadow-none"><p className="text-sm font-bold text-amber-600">Nenhum pedido na fila.</p></Card>
        ) : (
          allQueueItems.map((item) => (
            <Card key={item.order.id} className="p-4 md:p-5 border border-orange-50 bg-white">
              <div className="flex flex-col md:flex-row justify-between items-center gap-4">

                {/* Esquerda: Empresa */}
                <div className="flex items-center gap-4 flex-1 w-full">
                  <div className="relative">
                    <img src={item.company.logoUrl} className="h-12 w-12 rounded-xl object-cover border border-orange-50 shadow-sm" />
                    <div className="absolute -bottom-1 -right-1 h-5 w-5 rounded-full border-2 border-white flex items-center justify-center bg-orange-500">
                      <CalendarDaysIcon className="h-2.5 w-2.5 text-white" />
                    </div>
                  </div>
                  <div className="min-w-0">
                    <h3 className="text-base font-black text-amber-900 truncate">{item.company.name}</h3>
                    <div className="flex items-center gap-2 mt-0.5">
                      <span className={`text-[9px] font-black px-1.5 py-0.5 rounded ${item.isDraft ? 'bg-amber-100 text-amber-700' : 'bg-orange-100 text-orange-700'} uppercase`}>
                        {item.isDraft ? 'PREVISÃO' : 'PENDENTE'}
                      </span>
                      <span className="text-[10px] font-bold text-orange-400 uppercase">
                        {new Date(item.order.date + 'T12:00:00Z').toLocaleDateString('pt-BR', { day: '2-digit', month: 'long' })}
                      </span>
                    </div>
                  </div>
                </div>

                {/* Centro: Produtos Chips */}
                <div className="flex flex-wrap gap-2 flex-[2] justify-start md:justify-center w-full">
                  {item.order.items.map((it: any, idx: number) => (
                    <div key={idx} className="bg-orange-50/50 px-3 py-1.5 rounded-lg border border-orange-100/50 flex items-center gap-3">
                      <span className="text-xs font-bold text-amber-800">{it.productName}</span>
                      <span className="text-xs font-black text-orange-600">{it.quantity}</span>
                    </div>
                  ))}
                </div>

                {/* Direita: Ações (Apenas Ícones) */}
                <div className="flex items-center gap-1 w-full md:w-auto justify-end">
                  <button onClick={() => setEditingItem(item)} className="p-2.5 text-amber-400 hover:text-amber-600 transition-colors" title="Editar"><PencilSquareIcon className="h-6 w-6" /></button>
                  <button onClick={() => onDeleteOrder(item.order.id, item.company.id)} className="p-2.5 text-red-200 hover:text-red-400 transition-colors" title="Remover"><TrashIcon className="h-6 w-6" /></button>
                </div>

              </div>
            </Card>
          ))
        )}
      </div>
      <p className="text-center text-[10px] font-black text-amber-200 uppercase tracking-widest pt-4">Fim da lista de produção</p>
    </div>
  );
};

export default ScheduledConfirmation;

import React, { useState, useEffect } from 'react';
import { Company, Employee, Order, Product, CompanyProductSetting, RecurringOrderConfig } from './types';
import Sidebar from './components/Sidebar';
import CompanyManagement from './components/CompanyProfile';
import EmployeeManagement from './components/EmployeeManagement';
import { BuildingStorefrontIcon, UsersIcon, ClipboardDocumentListIcon, TagIcon, ShoppingBagIcon, CheckCircleIcon } from './components/Icons';
import LoginPage from './components/LoginPage';
import OrderManagement from './components/OrderManagement';
import ProductManagement from './components/ProductManagement';
import CompanyDetailView from './components/CompanyDetailView';
import ScheduledConfirmation from './components/ScheduledConfirmation';

type View = 'companies' | 'employees' | 'orders' | 'door-sales' | 'products' | 'scheduled-confirmation';

const loadFromLocalStorage = <T,>(key: string, defaultValue: T): T => {
    try {
        const storedValue = localStorage.getItem(key);
        if (storedValue) return JSON.parse(storedValue);
    } catch (error) { console.error(`Error loading ${key}`, error); }
    return defaultValue;
};

const saveToLocalStorage = <T,>(key: string, value: T) => {
    try { localStorage.setItem(key, JSON.stringify(value)); } catch (error) { console.error(`Error saving ${key}`, error); }
};

const initialCompanies: Company[] = [
    {
      id: '1',
      name: 'Padaria Doce Pão',
      cnpj: '12.345.678/0001-99',
      address: 'Rua das Flores, 123, São Paulo - SP',
      cep: '01234-567',
      phone: '(11) 98765-4321',
      logoUrl: 'https://picsum.photos/seed/bakerylogo/200',
      doorSale: true,
      orders: [],
      productSettings: [
        { productId: 'prod-1', buys: true, price: 0.75 },
        { productId: 'prod-2', buys: true, price: 5.50 }
      ]
    }
];

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);
  const [currentView, setCurrentView] = useState<View>('companies');
  const [companies, setCompanies] = useState<Company[]>(() => loadFromLocalStorage('companies', initialCompanies));
  const [employees, setEmployees] = useState<Employee[]>(() => loadFromLocalStorage('employees', []));
  const [products, setProducts] = useState<Product[]>(() => loadFromLocalStorage('products', []));
  const [selectedCompanyId, setSelectedCompanyId] = useState<string | null>(null);
  const [viewingCompanyId, setViewingCompanyId] = useState<string | null>(null);

  useEffect(() => { saveToLocalStorage('companies', companies); }, [companies]);
  useEffect(() => { saveToLocalStorage('employees', employees); }, [employees]);
  useEffect(() => { saveToLocalStorage('products', products); }, [products]);

  // Função Unificada para Confirmar Toda a Fila
  const handleConfirmAllQueue = (data: { drafts: any[], existing: any[] }) => {
    setCompanies(prev => {
      const updated = prev.map(c => {
        let companyOrders = [...c.orders];

        // 1. Confirmar pedidos pendentes existentes
        const existingForThisCompany = data.existing.filter(e => e.companyId === c.id);
        if (existingForThisCompany.length > 0) {
          const idsToConfirm = existingForThisCompany.map(e => e.orderId);
          companyOrders = companyOrders.map(o => 
            idsToConfirm.includes(o.id) ? { ...o, status: 'confirmed' as const } : o
          );
        }

        // 2. Oficializar previsões (drafts) como pedidos confirmados
        const draftsForThisCompany = data.drafts.filter(d => d.companyId === c.id);
        if (draftsForThisCompany.length > 0) {
          const newConfirmedOrders: Order[] = draftsForThisCompany.map(d => ({
            ...d.order,
            id: `ord-conf-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
            status: 'confirmed' as const
          }));
          companyOrders = [...newConfirmedOrders, ...companyOrders];
        }

        return { ...c, orders: companyOrders };
      });
      return updated;
    });

    // Feedback de sucesso
    const total = data.drafts.length + data.existing.length;
    alert(`Sucesso! ${total} pedido(s) foram confirmados e enviados para o histórico.`);
  };

  const handleUpdateRecurringOrder = (companyId: string, config: RecurringOrderConfig) => {
    setCompanies(prev => prev.map(c => c.id === companyId ? { ...c, recurringOrder: config } : c));
  };

  const handleLogin = (user: string, pass: string): boolean => {
    if (user === 'admin' && pass === 'admin') {
      setIsAuthenticated(true);
      return true;
    }
    return false;
  };

  const handleLogout = () => { setIsAuthenticated(false); setViewingCompanyId(null); };

  const handleSetCurrentView = (view: View) => {
    setCurrentView(view);
    setViewingCompanyId(null);
    const filtered = view === 'door-sales' ? companies.filter(c => c.doorSale) : companies; 
    setSelectedCompanyId(filtered.length > 0 ? filtered[0].id : null);
  }

  const handleAddCompany = (newCompanyData: Omit<Company, 'id' | 'orders'>) => {
    const newCompany: Company = { ...newCompanyData, id: Date.now().toString(), orders: [], productSettings: [] };
    setCompanies(prev => [...prev, newCompany]);
  };

  const handleUpdateCompany = (updatedCompany: Company) => {
    setCompanies(prev => prev.map(c => c.id === updatedCompany.id ? updatedCompany : c));
  };

  const handleDeleteCompany = (companyId: string) => {
    const remaining = companies.filter(c => c.id !== companyId);
    setCompanies(remaining);
    if (selectedCompanyId === companyId) setSelectedCompanyId(remaining.length > 0 ? remaining[0].id : null);
  };

  const handleAddOrder = (newOrderData: Omit<Order, 'id'>, companyId?: string) => {
    const targetId = companyId || selectedCompanyId;
    if (!targetId) return;
    setCompanies(prev => prev.map(c => {
      if (c.id === targetId) {
        const newOrder: Order = { ...newOrderData, id: `order-manual-${Date.now()}`, status: 'pending' as const };
        return { ...c, orders: [newOrder, ...c.orders].sort((a, b) => b.date.localeCompare(a.date)) };
      }
      return c;
    }));
  };

  const handleDeleteOrder = (orderId: string, companyId?: string) => {
    const targetId = companyId || selectedCompanyId;
    if (!targetId) return;
    setCompanies(prev => prev.map(c => c.id === targetId ? { ...c, orders: c.orders.filter(o => o.id !== orderId) } : c));
  };

  const handleUpdateOrderSignature = (orderId: string, signature: string) => {
    if (!selectedCompanyId) return;
    setCompanies(prev => prev.map(c => c.id === selectedCompanyId ? { ...c, orders: c.orders.map(o => o.id === orderId ? { ...o, signature } : o) } : c));
  };

  const renderContent = () => {
    const selectedCompany = companies.find(c => c.id === selectedCompanyId) || null;
    const companyToView = companies.find(c => c.id === viewingCompanyId);

    if (currentView === 'companies' && companyToView) {
      return <CompanyDetailView company={companyToView} products={products} onUpdate={handleUpdateCompany} onUpdateProductSettings={(id, s) => setCompanies(prev => prev.map(c => c.id === id ? { ...c, productSettings: s } : c))} onBack={() => setViewingCompanyId(null)} />
    }

    switch (currentView) {
      case 'companies': return <CompanyManagement companies={companies} onAdd={handleAddCompany} onUpdate={handleUpdateCompany} onDelete={handleDeleteCompany} onViewCompany={setViewingCompanyId} />;
      case 'employees': return <EmployeeManagement employees={employees} onAddEmployee={(e) => setEmployees(prev => [...prev, { ...e, id: `emp-${Date.now()}`, status: 'Ativo' }])} onDeleteEmployee={(id) => setEmployees(prev => prev.filter(e => e.id !== id))} onUpdateEmployeeStatus={(id, s) => setEmployees(prev => prev.map(e => e.id === id ? { ...e, status: s } : e))} />;
      case 'scheduled-confirmation': return <ScheduledConfirmation companies={companies} products={products} onConfirmAllQueue={handleConfirmAllQueue} onDeleteOrder={handleDeleteOrder} onAddManualOrder={handleAddOrder} />;
      case 'orders': return <OrderManagement companies={companies} selectedCompany={selectedCompany} products={products} onSelectCompany={setSelectedCompanyId} onAddOrder={handleAddOrder} onDeleteOrder={(id) => handleDeleteOrder(id)} onUpdateOrderSignature={handleUpdateOrderSignature} onUpdateRecurringOrder={handleUpdateRecurringOrder} isDoorSaleMode={false} />;
      case 'door-sales': return <OrderManagement companies={companies.filter(c => c.doorSale)} selectedCompany={selectedCompany} products={products} onSelectCompany={setSelectedCompanyId} onAddOrder={handleAddOrder} onDeleteOrder={(id) => handleDeleteOrder(id)} onUpdateOrderSignature={handleUpdateOrderSignature} isDoorSaleMode={true} />;
      case 'products': return <ProductManagement products={products} onAdd={(p) => setProducts(prev => [...prev, { ...p, id: `prod-${Date.now()}` }])} onUpdate={(p) => setProducts(prev => prev.map(prod => prod.id === p.id ? p : prod))} onDelete={(id) => setProducts(prev => prev.filter(p => p.id !== id))} />;
      default: return null;
    }
  };

  if (!isAuthenticated) return <LoginPage onLogin={handleLogin} />;

  const headerInfo = {
    companies: { icon: <BuildingStorefrontIcon className="h-8 w-8 text-orange-500" />, title: 'Gerenciamento de Empresas', subtitle: 'Adicione, visualize e edite as informações das suas empresas clientes.' },
    employees: { icon: <UsersIcon className="h-8 w-8 text-orange-500" />, title: 'Gerenciamento de Funcionários', subtitle: 'Gerencie a equipe da Engenho do Pão.' },
    'scheduled-confirmation': { icon: <CheckCircleIcon className="h-8 w-8 text-orange-500" />, title: 'Fila de Produção & Confirmação', subtitle: 'Gerencie todos os pedidos aguardando confirmação (agendados e manuais).' },
    orders: { icon: <ClipboardDocumentListIcon className="h-8 w-8 text-orange-500" />, title: 'Histórico de pedidos', subtitle: 'Acompanhe o registro histórico de pedidos de todos os clientes.' },
    'door-sales': { icon: <ShoppingBagIcon className="h-8 w-8 text-orange-500" />, title: 'Venda na Porta', subtitle: 'Gerencie pedidos específicos de venda na porta.' },
    products: { icon: <TagIcon className="h-8 w-8 text-orange-500" />, title: 'Gerenciamento de Produtos', subtitle: 'Cadastre e organize os produtos oferecidos pela padaria.' },
  };

  return (
    <div className="flex h-screen bg-orange-50 font-sans">
      <Sidebar currentView={currentView} setCurrentView={handleSetCurrentView} onLogout={handleLogout} />
      <main className="flex-1 p-4 md:p-8 overflow-y-auto">
        {!(currentView === 'companies' && viewingCompanyId) && (
          <header className="mb-8">
              <div className="flex items-center gap-4">
                  {headerInfo[currentView].icon}
                  <h1 className="text-3xl font-bold text-amber-800">{headerInfo[currentView].title}</h1>
              </div>
              <p className="text-amber-600 mt-1">{headerInfo[currentView].subtitle}</p>
          </header>
        )}
        {renderContent()}
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Company, Order, OrderItem, Product } from '../types';
import Card from './common/Card';
import Button from './common/Button';
import { CheckCircleIcon, CalendarDaysIcon, RocketLaunchIcon, TrashIcon, PencilSquareIcon, XMarkIcon, PlusIcon } from './Icons';

const getLocalDateStr = (date: Date) => {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

const EditOrderModal = ({ order, products, onSave, onClose }: any) => {
  const [items, setItems] = useState<Omit<OrderItem, 'id'>[]>(
    order.order.items.map((it: any) => ({ productName: it.productName, quantity: it.quantity }))
  );

  const handleItemChange = (index: number, field: 'productName' | 'quantity', value: any) => {
    const newItems = [...items];
    if (field === 'quantity') {
      newItems[index].quantity = Math.max(1, Number(value));
    } else {
      newItems[index].productName = value;
    }
    setItems(newItems);
  };

  const addItem = () => setItems([...items, { productName: '', quantity: 1 }]);
  const removeItem = (index: number) => setItems(items.filter((_, i) => i !== index));

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const validItems = items.filter(it => it.productName !== '');
    if (validItems.length === 0) return;
    onSave(validItems);
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-amber-900/40 z-50 flex items-center justify-center p-4 backdrop-blur-sm animate-fade-in">
      <Card className="w-full max-w-lg shadow-2xl border-none">
        <div className="p-6 border-b border-orange-50 flex justify-between items-center bg-white rounded-t-xl">
          <div className="flex items-center gap-3">
            <img src={order.company.logoUrl} className="h-10 w-10 rounded-lg object-cover" />
            <h3 className="text-lg font-black text-amber-900">Editar Pedido - {order.company.name}</h3>
          </div>
          <button onClick={onClose} className="text-amber-400 hover:text-amber-600"><XMarkIcon className="h-6 w-6" /></button>
        </div>
        <form onSubmit={handleSubmit} className="p-8 space-y-5 bg-white rounded-b-xl max-h-[70vh] overflow-y-auto">
          <div className="space-y-3">
            {items.map((item, index) => (
              <div key={index} className="flex gap-2 items-end">
                <div className="flex-1">
                  <select 
                    value={item.productName} 
                    onChange={e => handleItemChange(index, 'productName', e.target.value)}
                    className="w-full px-3 py-2 bg-orange-50/30 border border-orange-100 rounded-lg text-sm"
                  >
                    <option value="">Produto...</option>
                    {products.map((p: any) => <option key={p.id} value={p.name}>{p.name}</option>)}
                  </select>
                </div>
                <div className="w-20">
                  <input type="number" value={item.quantity} onChange={e => handleItemChange(index, 'quantity', e.target.value)} className="w-full px-3 py-2 border rounded-lg text-center font-black" />
                </div>
                <button type="button" onClick={() => removeItem(index)} className="text-red-300 p-2"><TrashIcon className="h-5 w-5" /></button>
              </div>
            ))}
            <button type="button" onClick={addItem} className="text-xs font-black text-orange-600 flex items-center gap-1"><PlusIcon className="h-4 w-4" /> ADICIONAR ITEM</button>
          </div>
          <div className="pt-6 flex gap-3">
            <Button type="button" variant="secondary" onClick={onClose} className="flex-1">Cancelar</Button>
            <Button type="submit" className="flex-1">Salvar Alterações</Button>
          </div>
        </form>
      </Card>
    </div>
  );
};

interface ScheduledConfirmationProps {
  companies: Company[];
  products: Product[];
  onConfirmAllQueue: (data: { drafts: any[], existing: any[] }) => void;
  onDeleteOrder: (orderId: string, companyId: string) => void;
  onAddManualOrder: (order: Omit<Order, 'id'>, companyId: string) => void;
}

const ScheduledConfirmation: React.FC<ScheduledConfirmationProps> = ({ companies, products, onConfirmAllQueue, onDeleteOrder, onAddManualOrder }) => {
  const [editingItem, setEditingItem] = useState<any>(null);

  const tomorrowStr = getLocalDateStr(new Date(Date.now() + 86400000));
  const tomorrowDay = new Date(Date.now() + 86400000).getDay();

  // Pedidos reais pendentes (manuais ou já gerados)
  const pendingOrders = companies.flatMap(c => 
    c.orders.filter(o => o.status === 'pending').map(o => ({ company: c, order: o, isDraft: false }))
  );

  // Previsões para amanhã baseadas na recorrência
  const draftOrders = companies
    .filter(c => {
      if (!c.recurringOrder || c.orders.some(o => o.date === tomorrowStr)) return false;
      const { type, daysOfWeek } = c.recurringOrder.recurrence;
      return daysOfWeek?.includes(tomorrowDay) || type === 'daily' || (type === 'weekdays' && tomorrowDay >= 1 && tomorrowDay <= 5);
    })
    .map(c => ({
      company: c,
      order: {
        id: `draft-${c.id}`,
        date: tomorrowStr,
        items: c.recurringOrder!.items,
        status: 'pending' as const
      },
      isDraft: true
    }));

  const allQueueItems = [...pendingOrders, ...draftOrders].sort((a, b) => a.order.date.localeCompare(b.order.date));

  const handleConfirmAll = () => {
    if (allQueueItems.length === 0) return;

    // Passamos todos os dados necessários para o App.tsx processar
    onConfirmAllQueue({
      drafts: draftOrders.map(d => ({ 
        companyId: d.company.id, 
        order: { ...d.order, items: d.order.items.map(it => ({ ...it, id: Math.random().toString() })) } 
      })),
      existing: pendingOrders.map(p => ({ 
        companyId: p.company.id, 
        orderId: p.order.id 
      }))
    });
  };

  const handleSaveEdit = (newItems: any) => {
    if (!editingItem) return;
    if (!editingItem.isDraft) onDeleteOrder(editingItem.order.id, editingItem.company.id);
    onAddManualOrder({ 
      date: editingItem.order.date, 
      items: newItems.map((it: any) => ({ ...it, id: Math.random().toString() })), 
      status: 'pending' 
    }, editingItem.company.id);
  };

  return (
    <div className="space-y-6 animate-fade-in max-w-5xl mx-auto pb-10">
      {editingItem && <EditOrderModal order={editingItem} products={products} onSave={handleSaveEdit} onClose={() => setEditingItem(null)} />}

      {/* Cabeçalho com o Botão 'Box' Estilizado */}
      <div className="flex flex-col sm:flex-row justify-between items-center bg-white p-6 rounded-2xl shadow-sm border border-orange-100 gap-6">
        <div>
          <h2 className="text-xl font-black text-amber-900 leading-tight">Fila de Produção</h2>
          <p className="text-xs font-bold text-amber-500 uppercase tracking-tighter">PEDIDOS ATIVOS E PREVISÕES</p>
        </div>

        {/* Botão de Confirmação Principal conforme o Print */}
        <button 
          onClick={handleConfirmAll}
          disabled={allQueueItems.length === 0}
          className="flex flex-col items-center justify-center p-4 bg-white border-2 border-black rounded-xl hover:bg-orange-50 transition-all disabled:opacity-30 disabled:grayscale group"
        >
          <RocketLaunchIcon className="h-8 w-8 text-black mb-1 transform group-hover:-translate-y-1 transition-transform" />
          <span className="text-sm font-bold text-black px-4">
