// Modal de Assinatura (Canvas)
const SignatureModal = ({ onSave, onClose }: { onSave: (signature: string) => void, onClose: () => void }) => {
  const canvasRef = React.useRef<HTMLCanvasElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);

  React.useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    ctx.strokeStyle = '#000';
    ctx.lineWidth = 3;
    ctx.lineCap = 'round';
  }, []);

  const getPos = (e: React.MouseEvent | React.TouchEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    const clientX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : (e as React.MouseEvent).clientY;
    return {
      x: clientX - rect.left,
      y: clientY - rect.top
    };
  };

  const startDrawing = (e: React.MouseEvent | React.TouchEvent) => {
    setIsDrawing(true);
    const pos = getPos(e);
    const ctx = canvasRef.current?.getContext('2d');
    ctx?.beginPath();
    ctx?.moveTo(pos.x, pos.y);
  };

  const draw = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawing) return;
    const pos = getPos(e);
    const ctx = canvasRef.current?.getContext('2d');
    ctx?.lineTo(pos.x, pos.y);
    ctx?.stroke();
  };

  const stopDrawing = () => setIsDrawing(false);

  const clear = () => {
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (canvas && ctx) ctx.clearRect(0, 0, canvas.width, canvas.height);
  };

  const save = () => {
    const canvas = canvasRef.current;
    if (canvas) {
      const dataUrl = canvas.toDataURL('image/png');
      onSave(dataUrl);
    }
  };

  return (
    <div className="fixed inset-0 bg-amber-900/60 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
      <Card className="w-full max-w-lg bg-white p-6 shadow-2xl border-none">
        <div className="flex justify-between items-center mb-4">
          <h3 className="text-lg font-black text-amber-900 uppercase">Assinatura Digital</h3>
          <button onClick={onClose}><XMarkIcon className="h-6 w-6 text-gray-400" /></button>
        </div>
        <div className="border-2 border-dashed border-orange-200 rounded-2xl bg-orange-50/30 mb-6 overflow-hidden">
          <canvas
            ref={canvasRef}
            width={500}
            height={250}
            className="w-full h-56 cursor-crosshair touch-none bg-white"
            onMouseDown={startDrawing}
            onMouseMove={draw}
            onMouseUp={stopDrawing}
            onMouseLeave={stopDrawing}
            onTouchStart={startDrawing}
            onTouchMove={draw}
            onTouchEnd={stopDrawing}
          />
        </div>
        <div className="flex justify-between gap-3">
          <Button onClick={clear} variant="secondary" className="flex-1">Limpar</Button>
          <Button onClick={save} className="flex-1">Confirmar Assinatura</Button>
        </div>
      </Card>
    </div>
  );
};

interface OrderManagementProps {
  companies: Company[];
  selectedCompany: Company | null;
  products: Product[];
  onSelectCompany: (companyId: string) => void;
  onAddOrder: (order: Omit<Order, 'id'>) => void;
  onDeleteOrder: (orderId: string) => void;
  onUpdateOrderSignature?: (orderId: string, signature: string) => void;
  isDoorSaleMode?: boolean;
}

const OrderManagement: React.FC<OrderManagementProps> = ({ 
    companies, 
    selectedCompany, 
    products, 
    onSelectCompany, 
    onAddOrder, 
    onDeleteOrder, 
    onUpdateOrderSignature, 
    isDoorSaleMode = false 
}) => {
  const [signatureOrderId, setSignatureOrderId] = useState<string | null>(null);
  const [viewSignatureUrl, setViewSignatureUrl] = useState<string | null>(null);

  // Estado para o formulário de novo pedido
  const [newOrderItems, setNewOrderItems] = useState<{productName: string, quantity: number}[]>([{productName: '', quantity: 1}]);

  const handleAddItem = () => setNewOrderItems([...newOrderItems, {productName: '', quantity: 1}]);
  const handleRemoveItem = (idx: number) => setNewOrderItems(newOrderItems.filter((_, i) => i !== idx));
  const handleItemChange = (idx: number, field: string, value: any) => {
    const updated = [...newOrderItems];
    (updated[idx] as any)[field] = field === 'quantity' ? Math.max(1, Number(value)) : value;
    setNewOrderItems(updated);
  };

  const handleLaunchOrder = () => {
    const validItems = newOrderItems.filter(it => it.productName !== '');
    if (validItems.length === 0) return alert('Selecione ao menos um produto.');

    const today = new Date().toISOString().split('T')[0];
    onAddOrder({
      date: today,
      items: validItems.map(it => ({ ...it, id: Math.random().toString() })),
      status: 'confirmed' // Lança direto como confirmado
    });
    setNewOrderItems([{productName: '', quantity: 1}]);
  };

  const handleSaveSignature = (signature: string) => {
    if (signatureOrderId && onUpdateOrderSignature) {
      onUpdateOrderSignature(signatureOrderId, signature);
    }
    setSignatureOrderId(null);
  };

  const confirmedOrders = selectedCompany?.orders.filter(o => o.status === 'confirmed') || [];

  return (
    <div className="space-y-6 max-w-5xl mx-auto pb-12">
      {signatureOrderId && <SignatureModal onSave={handleSaveSignature} onClose={() => setSignatureOrderId(null)} />}
      {viewSignatureUrl && <ViewSignatureModal signature={viewSignatureUrl} onClose={() => setViewSignatureUrl(null)} />}

      {/* Seletor de Empresa */}
      <Card className="p-6 border border-orange-100 bg-white">
        <label className="block text-xs font-black text-amber-500 uppercase mb-2 tracking-tight">
            Cliente Selecionado
        </label>
        <select
            value={selectedCompany?.id || ''}
            onChange={(e) => onSelectCompany(e.target.value)}
            className="w-full max-w-md px-4 py-3 bg-orange-50/30 border border-orange-100 rounded-xl font-bold text-amber-900 outline-none focus:ring-2 focus:ring-orange-500 transition-all"
        >
            <option value="" disabled>-- Selecione a Empresa --</option>
            {companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
        </select>
      </Card>

      {selectedCompany && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 animate-fade-in">

            {/* Lançamento (Apenas Venda na Porta) */}
            {isDoorSaleMode && (
                <div className="lg:col-span-1 space-y-4">
                    <Card className="p-6 border border-orange-200 bg-white shadow-sm sticky top-6">
                        <div className="flex items-center gap-3 mb-6">
                            <RocketLaunchIcon className="h-6 w-6 text-orange-500" />
                            <h3 className="text-lg font-black text-amber-900 uppercase">Lançar Venda</h3>
                        </div>

                        <div className="space-y-4">
                            {newOrderItems.map((item, idx) => (
                                <div key={idx} className="flex gap-2 items-end bg-orange-50/30 p-3 rounded-xl border border-orange-100">
                                    <div className="flex-1">
                                        <label className="text-[10px] font-bold text-orange-400 uppercase ml-1">Produto</label>
                                        <select 
                                            value={item.productName} 
                                            onChange={e => handleItemChange(idx, 'productName', e.target.value)}
                                            className="w-full bg-white border border-orange-100 rounded-lg p-2 text-xs font-bold text-amber-900"
                                        >
                                            <option value="">...</option>
                                            {products.map(p => <option key={p.id} value={p.name}>{p.name}</option>)}
                                        </select>
                                    </div>
                                    <div className="w-16">
                                        <label className="text-[10px] font-bold text-orange-400 uppercase ml-1">Qtd</label>
                                        <input 
                                            type="number" 
                                            value={item.quantity} 
                                            onChange={e => handleItemChange(idx, 'quantity', e.target.value)}
                                            className="w-full bg-white border border-orange-100 rounded-lg p-2 text-xs font-black text-center"
                                        />
                                    </div>
                                    <button onClick={() => handleRemoveItem(idx)} className="p-2 text-red-300 hover:text-red-500 transition-colors">
                                        <TrashIcon className="h-5 w-5" />
                                    </button>
                                </div>
                            ))}

                            <button onClick={handleAddItem} className="w-full py-2 border-2 border-dashed border-orange-200 rounded-xl text-[10px] font-black text-orange-500 uppercase hover:bg-orange-50 transition-all">
                                + Adicionar Produto
                            </button>

                            <Button onClick={handleLaunchOrder} className="w-full mt-4 py-3 shadow-lg shadow-orange-200">
                                Confirmar e Lançar
                            </Button>
                        </div>
                    </Card>
                </div>
            )}

            {/* Histórico */}
            <div className={`${isDoorSaleMode ? 'lg:col-span-2' : 'lg:col-span-3'} space-y-4`}>
                <div className="flex items-center gap-3 mb-2 px-2">
                    <ClipboardDocumentListIcon className="h-5 w-5 text-amber-600" />
                    <h3 className="text-sm font-black text-amber-800 uppercase">Histórico Recente</h3>
                </div>

                {confirmedOrders.length > 0 ? (
                    confirmedOrders.map(order => (
                        <Card key={order.id} className="p-5 border border-orange-50 bg-white hover:border-orange-200 transition-all group">
                            <div className="flex flex-col md:flex-row justify-between items-center gap-6">

                                {/* Info do Pedido */}
                                <div className="flex-1 w-full">
                                    <p className="text-[10px] font-black text-orange-400 uppercase tracking-tighter mb-1">
                                        {new Date(order.date + 'T12:00:00Z').toLocaleDateString('pt-BR', { day: '2-digit', month: 'long', year: 'numeric' })}
                                    </p>
                                    <div className="flex flex-wrap gap-1.5">
                                        {order.items.map((it, idx) => (
                                            <span key={idx} className="bg-orange-50 px-2 py-1 rounded-lg text-[11px] font-bold text-amber-800 border border-orange-100">
                                                {it.productName} <span className="text-orange-600 font-black ml-1">{it.quantity}</span>
                                            </span>
                                        ))}
                                    </div>
                                </div>

                                {/* Seção de Assinatura */}
                                <div className="flex items-center gap-4 w-full md:w-auto justify-end border-t md:border-t-0 pt-4 md:pt-0 border-orange-50">
                                    {isDoorSaleMode && (
                                        <div className="flex-shrink-0">
                                            {order.signature ? (
                                                <div className="flex items-center gap-2">
                                                    <div className="bg-green-100 text-green-700 px-3 py-1.5 rounded-full flex items-center gap-2 text-[10px] font-black uppercase">
                                                        <CheckCircleIcon className="h-4 w-4" /> Assinado
                                                    </div>
                                                    <button onClick={() => setViewSignatureUrl(order.signature!)} className="p-2 bg-white border border-green-100 rounded-lg text-green-600 hover:bg-green-50 transition-all shadow-sm">
                                                        <EyeIcon className="h-5 w-5" />
                                                    </button>
                                                </div>
                                            ) : (
                                                <button 
                                                    onClick={() => setSignatureOrderId(order.id)}
                                                    className="flex items-center gap-2 bg-orange-500 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase hover:bg-orange-600 transition-all shadow-md shadow-orange-100 animate-pulse-slow"
                                                >
                                                    <PencilSquareIcon className="h-4 w-4" /> Assinar Agora
                                                </button>
                                            )}
                                        </div>
                                    )}
                                    <button onClick={() => onDeleteOrder(order.id)} className="p-2 text-red-100 hover:text-red-400 transition-colors">
                                        <TrashIcon className="h-5 w-5" />
                                    </button>
                                </div>
                            </div>
                        </Card>
                    ))
                ) : (
                    <div className="text-center p-16 bg-white/40 border-2 border-dashed border-orange-100 rounded-3xl">
                        <ClipboardDocumentListIcon className="mx-auto h-12 w-12 text-orange-100" />
                        <p className="mt-4 text-xs font-bold text-amber-400 uppercase">Nenhum pedido lançado hoje.</p>
                    </div>
                )}
            </div>
        </div>
      )}

      {!selectedCompany && (
        <Card className="text-center p-20 border-dashed border-2 border-orange-100 bg-white/50">
            <BuildingStorefrontIcon className="mx-auto h-16 w-16 text-orange-100 mb-4" />
            <h3 className="text-lg font-black text-amber-900 uppercase">Selecione uma Empresa</h3>
            <p className="text-sm text-amber-500 font-medium">Escolha um cliente acima para gerenciar as vendas e assinaturas.</p>
        </Card>
      )}
    </div>
  );
};

