import React, { useState } from 'react';
import { Employee } from '../types';
import Card from './common/Card';
import Input from './common/Input';
import Button from './common/Button';
import { TrashIcon, UserPlusIcon, PlusIcon } from './Icons';

interface EmployeeManagementProps {
  employees: Employee[];
  onAddEmployee: (employee: Omit<Employee, 'id' | 'status'>) => void;
  onDeleteEmployee: (employeeId: string) => void;
  onUpdateEmployeeStatus: (employeeId: string, status: Employee['status']) => void;
}

const EmployeeManagement: React.FC<EmployeeManagementProps> = ({ 
  employees, 
  onAddEmployee, 
  onDeleteEmployee,
  onUpdateEmployeeStatus
}) => {
  const [showForm, setShowForm] = useState(false);
  const [newEmployee, setNewEmployee] = useState({
    name: '',
    role: '',
    admissionDate: '',
    salary: 0,
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type } = e.target;
    setNewEmployee(prev => ({
      ...prev,
      [name]: type === 'number' && value ? parseFloat(value) : value
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newEmployee.name && newEmployee.role && newEmployee.admissionDate) {
      onAddEmployee(newEmployee);
      setNewEmployee({ name: '', role: '', admissionDate: '', salary: 0 });
      setShowForm(false);
    }
  };

  return (
    <div className="space-y-8 animate-fade-in">
      <div className="flex justify-between items-center">
        <h3 className="text-xl font-bold text-amber-900 uppercase tracking-tight">Equipe Engenho do Pão</h3>
        <Button onClick={() => setShowForm(!showForm)}>
            {showForm ? 'Cancelar' : (
                <>
                    <UserPlusIcon className="h-5 w-5 mr-2"/>
                    Novo Funcionário
                </>
            )}
        </Button>
      </div>

      {showForm && (
        <Card className="border border-orange-100 shadow-xl rounded-2xl animate-fade-in">
          <form onSubmit={handleSubmit} className="p-8">
            <h4 className="text-lg font-bold text-amber-800 mb-6">Cadastrar Novo Funcionário</h4>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <Input label="Nome Completo" name="name" value={newEmployee.name} onChange={handleChange} required />
              <Input label="Cargo" name="role" value={newEmployee.role} onChange={handleChange} required />
              <Input label="Data de Admissão" name="admissionDate" type="date" value={newEmployee.admissionDate} onChange={handleChange} required />
              <Input label="Salário (R$)" name="salary" type="number" step="0.01" min="0" value={newEmployee.salary || ''} onChange={handleChange} required />
            </div>
            <div className="mt-8 flex justify-end gap-3">
                <Button type="button" variant="secondary" onClick={() => setShowForm(false)}>Cancelar</Button>
                <Button type="submit">
                    <PlusIcon className="h-5 w-5 mr-2" />
                    Adicionar Funcionário
                </Button>
            </div>
          </form>
        </Card>
      )}

      <Card className="rounded-2xl overflow-hidden border border-orange-100">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-orange-50 border-b border-orange-100">
              <tr>
                <th className="p-5 text-xs font-bold text-amber-800 uppercase tracking-widest">Nome</th>
                <th className="p-5 text-xs font-bold text-amber-800 uppercase tracking-widest">Cargo</th>
                <th className="p-5 text-xs font-bold text-amber-800 uppercase tracking-widest">Admissão</th>
                <th className="p-5 text-xs font-bold text-amber-800 uppercase tracking-widest">Salário</th>
                <th className="p-5 text-xs font-bold text-amber-800 uppercase tracking-widest text-center">Status</th>
                <th className="p-5 text-xs font-bold text-amber-800 uppercase tracking-widest text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-orange-50">
              {employees.map(employee => (
                <tr key={employee.id} className="hover:bg-orange-50/30 transition-colors">
                  <td className="p-5 font-bold text-amber-900">{employee.name}</td>
                  <td className="p-5 text-amber-700 text-sm">{employee.role}</td>
                  <td className="p-5 text-amber-700 text-sm">{new Date(employee.admissionDate).toLocaleDateString('pt-BR', { timeZone: 'UTC' })}</td>
                  <td className="p-5 text-amber-700 text-sm font-semibold">{employee.salary.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}</td>
                  <td className="p-5 text-center">
                    <select
                        value={employee.status}
                        onChange={(e) => onUpdateEmployeeStatus(employee.id, e.target.value as Employee['status'])}
                        className={`w-24 text-center appearance-none cursor-pointer rounded-full px-3 py-1 text-[10px] font-black uppercase border ${employee.status === 'Ativo' ? 'bg-green-100 text-green-700 border-green-200' : 'bg-red-100 text-red-700 border-red-200'} focus:outline-none`}
                    >
                        <option value="Ativo">Ativo</option>
                        <option value="Inativo">Inativo</option>
                    </select>
                  </td>
                  <td className="p-5 text-right">
                    <button onClick={() => onDeleteEmployee(employee.id)} className="text-red-300 hover:text-red-500 p-2 rounded-full hover:bg-red-50 transition-all" aria-label="Deletar funcionário">
                      <TrashIcon className="h-5 w-5" />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {employees.length === 0 && (
            <div className="text-center p-12 bg-white">
               <p className="text-sm font-bold text-amber-400 uppercase tracking-widest">Nenhum funcionário cadastrado.</p>
            </div>
          )}
        </div>
      </Card>
    </div>
  );
};

export default EmployeeManagement;

import React, { useState } from 'react';
import { Product } from '../types';
import Card from './common/Card';
import Input from './common/Input';
import Button from './common/Button';
import { TrashIcon, TagIcon, PencilIcon, PlusIcon, XMarkIcon } from './Icons';

// Modal Component
const ProductModal = ({ product, onSave, onClose }: { product: Partial<Product> | null, onSave: (product: Omit<Product, 'id'> | Product) => void, onClose: () => void }) => {
  if (!product) return null;

  const [formData, setFormData] = useState({
    name: product.name || '',
    category: product.category || '',
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ 
        ...prev, 
        [name]: value 
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.category) {
        alert("Nome e categoria são obrigatórios.");
        return;
    }
    const finalData = { ...product, ...formData };
    onSave(finalData);
  };

  const isEditing = 'id' in product && product.id;

  return (
    <div className="fixed inset-0 bg-amber-900/40 z-50 flex items-center justify-center p-4 backdrop-blur-sm animate-fade-in" role="dialog" aria-modal="true">
      <Card className="w-full max-w-lg relative rounded-2xl shadow-2xl border-none">
        <button onClick={onClose} className="absolute top-5 right-5 text-amber-300 hover:text-amber-600 transition-colors" aria-label="Fechar">
          <XMarkIcon className="h-6 w-6" />
        </button>
        <form onSubmit={handleSubmit} className="p-10">
          <h3 className="text-2xl font-black text-amber-900 mb-8 uppercase tracking-tight">
            {isEditing ? 'Editar Produto' : 'Novo Produto'}
          </h3>
          <div className="space-y-6">
            <Input label="Nome do Produto" name="name" value={formData.name} onChange={handleChange} required placeholder="Ex: Pão de Sal" />
            <Input label="Categoria" name="category" value={formData.category} onChange={handleChange} required placeholder="Ex: Padaria" />
          </div>
          <div className="mt-10 flex justify-end gap-4">
            <Button type="button" variant="secondary" onClick={onClose}>Cancelar</Button>
            <Button type="submit">{isEditing ? 'Salvar Alterações' : 'Cadastrar Produto'}</Button>
          </div>
        </form>
      </Card>
    </div>
  );
};

interface ProductManagementProps {
  products: Product[];
  onAdd: (product: Omit<Product, 'id'>) => void;
  onUpdate: (product: Product) => void;
  onDelete: (productId: string) => void;
}

const ProductManagement: React.FC<ProductManagementProps> = ({ products, onAdd, onUpdate, onDelete }) => {
  const [modalProduct, setModalProduct] = useState<Partial<Product> | null>(null);

  const handleSave = (productData: Omit<Product, 'id'> | Product) => {
    if ('id' in productData && productData.id) {
        onUpdate(productData as Product);
    } else {
        onAdd(productData as Omit<Product, 'id'>);
    }
    setModalProduct(null);
  };

  return (
    <div className="space-y-8 animate-fade-in">
       <div className="flex justify-end">
        <Button onClick={() => setModalProduct({})}>
          <PlusIcon className="h-5 w-5 mr-2" />
          Adicionar Produto
        </Button>
      </div>

      <Card className="rounded-2xl border border-orange-100 overflow-hidden shadow-sm">
      {products.length > 0 ? (
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="bg-orange-50 border-b border-orange-100">
                <tr>
                  <th className="p-5 text-xs font-bold text-amber-800 uppercase tracking-widest">Produto</th>
                  <th className="p-5 text-xs font-bold text-amber-800 uppercase tracking-widest">Categoria</th>
                  <th className="p-5 text-xs font-bold text-amber-800 uppercase tracking-widest text-right">Ações</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-orange-50">
                {products.map(product => (
                  <tr key={product.id} className="hover:bg-orange-50/30 transition-colors">
                    <td className="p-5 font-bold text-amber-900">{product.name}</td>
                    <td className="p-5 text-amber-700 text-sm">{product.category}</td>
                    <td className="p-5 text-right">
                       <div className="flex gap-1 justify-end">
                          <button onClick={() => setModalProduct(product)} className="text-blue-300 hover:text-blue-500 p-2 rounded-full hover:bg-blue-50 transition-all" aria-label="Editar Produto">
                              <PencilIcon className="h-5 w-5" />
                          </button>
                          <button onClick={() => onDelete(product.id)} className="text-red-200 hover:text-red-500 p-2 rounded-full hover:bg-red-50 transition-all" aria-label="Deletar Produto">
                              <TrashIcon className="h-5 w-5" />
                          </button>
                        </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
      ) : (
         <div className="text-center p-20">
            <TagIcon className="mx-auto h-12 w-12 text-amber-100" />
            <h3 className="mt-4 text-sm font-bold text-amber-400 uppercase tracking-widest">Nenhum produto no catálogo</h3>
         </div>
      )}
      </Card>

      {modalProduct && <ProductModal product={modalProduct} onSave={handleSave} onClose={() => setModalProduct(null)} />}
    </div>
  );
};

export default ProductManagement;

import React, { useState } from 'react';
import Card from './common/Card';
