          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="bg-orange-50 border-b border-orange-100">
                <tr>
                  <th className="p-5 text-xs font-bold text-amber-800 uppercase tracking-widest">Produto</th>
                  <th className="p-5 text-xs font-bold text-amber-800 uppercase tracking-widest">Categoria</th>
                  <th className="p-5 text-xs font-bold text-amber-800 uppercase tracking-widest text-right">Ações</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-orange-50">
                {products.map(product => (
                  <tr key={product.id} className="hover:bg-orange-50/30 transition-colors group">
                    <td className="p-5 font-bold text-amber-900">{product.name}</td>
                    <td className="p-5 text-amber-700 text-sm">{product.category}</td>
                    <td className="p-5 text-right">
                       <div className="flex gap-1 justify-end opacity-0 group-hover:opacity-100 transition-opacity">
                          <button onClick={() => setModalProduct(product)} className="text-amber-400 hover:text-amber-600 p-2 rounded-full hover:bg-orange-50 transition-all" aria-label="Editar Produto">
                              <PencilIcon className="h-5 w-5" />
                          </button>
                          <button onClick={() => onDelete(product.id)} className="text-red-300 hover:text-red-500 p-2 rounded-full hover:bg-red-50 transition-all" aria-label="Deletar Produto">
                              <TrashIcon className="h-5 w-5" />
                          </button>
                        </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
      ) : (
         <div className="text-center p-20">
            <TagIcon className="mx-auto h-12 w-12 text-amber-100" />
            <h3 className="mt-4 text-sm font-bold text-amber-400 uppercase tracking-widest">Nenhum produto no catálogo</h3>
         </div>
      )}
      </Card>

      {modalProduct && <ProductModal product={modalProduct} onSave={handleSave} onClose={() => setModalProduct(null)} />}
    </div>
  );
};

export default ProductManagement;

